<template>
  <div id="dashboard">
     
       <div class="navbar-fixed">
       <nav>
            <div class="nav-wrapper">
            <router-link :to="{name:'dashboard', params: {email: email}}">
            <a href="#!" class="brand-logo"><img class="logo" src="../assets/img/NewLogo-01.svg" alt=""><p>| DASHBOARD</p></a>
            </router-link>
    
            <ul id="nav-mobile" class="right">
                <li >Welcome | <strong> {{email}}</strong></li>
                <li @click="logout()" ><i class="fa fa-sign-out fa-2x" aria-hidden="true" ></i></li> 
                <!-- <li><a href="badges.html"><i class="material-icons">view_module</i></a></li> -->
                <!-- <li><a href="collapsible.html"><i class="material-icons">refresh</i></a></li> -->
                <!-- <li style="right: 100px; position:relative;"> -->
                 
                <!-- </li> -->
                
                       
                    
            </ul>
            </div>
        </nav>


       </div>
 


    <ul id="slide-out" class="sidenav sidenav-fixed right-aligned z-depth-2">
      <!-- <li>
         <router-link :to="{name:'home', params: {email: email}}">
                    <i class="material-icons white-text">home</i> Home
        </router-link>
    </li> -->
    <v-collapsible collapse>
            <li>
            <v-collapsible-header>
                 <i class="material-icons white-text">home</i> <span class="white-text">Home</span> 
            </v-collapsible-header>
                <v-collapsible-body class="collap">
                        <li @click="toggleSidemenu()">
                            <router-link :to="{name:'home', params: {email: email}}">
                                        <i style="font-size: 22px;" class="fa fa-home white-text" aria-hidden="true"></i> <span class="white-text">Home</span>
                            </router-link>
                        </li>
                        <li @click="toggleSidemenu()">
                            <router-link :to="{name:'welcome', params: {email: email}}">
                                        <i style="font-size: 17px;" class="fa fa-handshake-o white-text" aria-hidden="true"></i> <span class="white-text">Welcome</span>
                            </router-link>
                        </li>
                        <li @click="toggleSidemenu()">
                            <router-link :to="{name:'topics', params: {email: email}}">
                                        <i style="font-size: 18px;" class="fa fa-list-alt white-text" aria-hidden="true"></i> <span class="white-text">Topics</span> 
                            </router-link>
                        </li>
                         <li @click="toggleSidemenu()">
                            <router-link :to="{name:'preacher', params: {email: email}}">
                                        <i style="font-size: 18px;" class="fa fa-user-o white-text" aria-hidden="true"></i> <span class="white-text">Preacher</span> 
                            </router-link>
                        </li>
                        <li @click="toggleSidemenu()">
                            <router-link :to="{name:'mission', params: {email: email}}">
                                        <i style="font-size: 18px;" class="fa fa-globe white-text" aria-hidden="true"></i><span class="white-text">Missions</span> 
                            </router-link>
                        </li>
                </v-collapsible-body>
            </li>
        
    </v-collapsible>
    <li @click="toggleSidemenu()">
         <router-link :to="{name:'calendar', params: {email: email}}">
                    <i class="material-icons white-text">event</i> Calendar
        </router-link>
    </li>
    <li @click="toggleSidemenu()">
        <router-link :to="{name:'audio', params: {email: email}}" >
                    <i class="material-icons white-text">audiotrack</i> Audio
        </router-link>
    </li>
    <li @click="toggleSidemenu()">
        <router-link :to="{name:'video', params: {email: email}}" >
                    <i class="material-icons white-text">ondemand_video</i> Video
        </router-link>
    </li>
    </ul>
        
   
            

     <div class="mainview">
              <div @click="toggleSidemenu()" class="sub-menu waves-effect waves-light hide-on-med-and-up right btn-floating btn-large"><i class="material-icons white-text">apps</i></div>
                <transition name="fade"> 
                  <router-view />
                </transition>
      </div>
         
      
  </div>
</template>

<script>
import firebase from 'firebase';

// import 'vuetify/dist/vuetify.min.css'


export default {
  name: 'Dashboard',
  props: ['email'],
  data(){
      return {
          isLoggedIn: false,
          currentUser: false,
            items: [
        'All', 'Family', 'Friends', 'Coworkers'
      ]
      }
  },
  methods:{
      logout(){
          firebase.auth().signOut().then(() => {
              this.$router.push('/miembros');
          })
      },
      toggleSidemenu(){

                $('#slide-out').toggleClass("show");
 
      },
  },
  mounted(){
 
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/materialize.min.css';

.sidenav {
    // left: 0!important;
    top: 64px;
    width: 200px!important;
    z-index: 9;
    background: #222!important;
    li>a {
        color:white!important;
    }
    li {
        transition: all .3s;
    }

    li:hover {
         transition: all .3s;
        background: rgba(255, 255, 255, 0.192);
    }
}

.chart {
    padding: 30px;
    margin-bottom: 20px;
}
.collap {
    background: linear-gradient(45deg, rgb(109, 47, 47) 0%, rgb(54, 98, 112) 100%);
}
p {
    left: 140px;
    font-size: 20px;
    top: -35px;
    width: 75vw;
    // line-height: 1px;
    position: relative;

    span {
        margin-top: 5px;
        position: relative;
        font-size: 14px;
        float: right;
        // right: 200px;
        strong {
            font-weight: 600;
            text-transform: uppercase;
        }
    }
}
.logo {
    left: 40px;
    position: relative;
    width: 80px;
    top: 10px;
}

#nav-mobile {

        li{
            position: relative;
            right: 20%;
            margin-right: 20px;
        }
   
}


.mainview {
    position: relative;
    width: 80%;
    left: 30px;
}

.navbar-fixed {
    z-index: 2;
}
nav {
        width: 92%!important;
        background:#222;

}




.right {
    
    li {
        transition: all .3s;
    }
    li:hover {
        transition: all .3s;
        cursor: pointer;
        opacity: .7;
    }
}

    
    @media screen and (max-width: 1024px) {
        .mainview {

            position: relative;
            width: 75%;
            left: 0%;
        }

        .sidenav {
            top: 64px;
            width: 180px!important;
                    font-size: 12px;
        
            span {
                font-size: 12px;
            }
        }
  .sidenav li>a {
        font-size: 12px!important;
    }
        nav {
        width: 100%!important;
        background:#222;

        }
            .brand-logo {

                position: relative;
              
                .logo {
                    left: 7vw;
                    position: relative;
                    width: 80px;
                    top: 10px;
                }
                p {
                    left: 18vw;
                }

            }

            #nav-mobile {

                li{
                    position: relative;
                    right: 0px;
                    margin-right: 10px;
                }
                    #slide-out {
    -webkit-transform: translateX(-105%);
    transform: translateX(-105%);
    transition: all .3s ease-in;
    
    }
   
}

    }

@media screen and (max-width: 748px) {
    .sidenav {
    // left: 0!important;
    top: 55px;
    }

    .right-aligned {
        right: 103% !important;
    }
    #slide-out {
    -webkit-transform: translateX(-105%);
    transform: translateX(-105%);
    transition: all .3s ease-in;
    
    }

  .show{
    -webkit-transform: translateX(105%) !important;
    transform: translateX(105%) !important;
        transition: all .3s ease-out;

  } 
    .sub-menu {
        position: fixed;
        bottom: 100px;
        right: 10px;
        z-index: 99;
        border: 1px solid white;
        transform: scale(-1, 1);
        background: $gradient-dark;
    }
    nav {
        width: 100%!important;
        background:#222;

}
     .mainview {

    position: relative;
    width: 100%;
    left: 0%;
    // top: 20px;
    // margin-right: -50%;
    // transform: translate(-50%, -50%);
}

#nav-mobile {

        li{
            position: relative;
            right: 0%;
            margin-right: 10px;
        }
   
}

    .brand-logo {
        height: 30px;
        .logo {
            width: 60px;
            top: 5px;
            left: 10px;

        }

        p {
            font-size: 14px;
            // margin-left: -50px;
            visibility: hidden;
        }
    }
}




</style>



