<template>
<div>
<loader v-if="loading"/>
 <div id="gallery" v-show="loading === false">


 
    <div class="parallax hide-on-small-only"></div>
    <!-- <div class="back"></div> -->
     <transition name="fadeUp">  
         <div class="wrapper" v-show="loading === false"> 
        <div class="masonry">

                <div v-for="(image, index) in output" :key="index" class="item">
                        <img :src="image.url"  alt=""  class="v-img z-depth-1 hoverable" @click="clickedImage(image); showingModal= true;"> 
                        
                        <div class ="centered">{{image.text}}</div>
                </div>   
        </div>
         </div>
    </transition>

  <transition name="slideUp">
               <div class="modalImage" id="addModal" v-if="showingModal" >
                <div class="modalContainerImages">
                    <div class="modalHeadingImage ">
                        <div class="closeImage" @click="showingModal = false;">
                            &times;
                        </div>
                        <div class="modalImages">
                            <img class="z-depth-5" :src="imageClicked.url" alt="">
                            <div class="img-info z-depth-5">
                                <p><strong>{{imageClicked.text}}</strong> | {{imageClicked.des}}</p>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
    </transition>
 </div>
 </div>
</template>

<script>
import json from '../assets/gallery/gallery.json';
import Loader from "../components/main/Loader.vue";

export default {
  name: 'Gallery',
  components:{
      "loader": Loader,
  },
  data(){
      return {
          loading: true,
          gallery_images: "",
          showingModal: false,
          imageClicked: '',
          photoURL: {},
          output: {},

            show   : false, // display content after API request
            offset : 5,     // items to display after scroll
            display: 5,     // initial items
            trigger: 300,   // how far from the bottom to trigger infinite scroll
            end    : false, // no more resources

      }
  },
  methods: {
      instaData: function(){

          var access_token = "efadf64726bd76295377877a5689a6dc";

                this.$http.get("https://api.flickr.com/services/rest/?&method=flickr.people.getPhotos&api_key="+ access_token +"&user_id=139127837@N05&extras=description&per_page=100&format=json&jsoncallback=?")
                    .then(response => {

                        var result = response.data.replace("jsonFlickrApi(", "").replace(')','');
                        var data = JSON.parse(result);
                        var photo = data.photos.photo;
                        var arr = [];
                        
                        for (var i = 0 ; i < photo.length; i++ ) {
                            var temp = {};
                            
                            temp['url'] = 'http://farm' + photo[i].farm + '.static.flickr.com/' + photo[i].server + '/' + photo[i].id + '_' + photo[i].secret + '_b.jpg';
                            temp['text'] = photo[i].title;
                            temp['des'] = photo[i].description._content;

                             arr.push(temp);
                        }

                        this.output = arr;
                        console.log(this.output)

                        setTimeout(() => {
                            this.loading = false;
                        }, 1000);


                    });

      },

      clickedImage(image){

          this.imageClicked = image;
      }
},
mounted(){
    this.instaData();
   
}
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/materialize.min.css';


html{
    background: #fff;
}

   #gallery {
        // margin-top: 50px;
        height: 100vh;

// .back {
//     height: 100vh;
//     width: 100%;
//     position: absolute;
//     opacity: .3;
//     overflow: hidden;
//     background: $gradient-2;

// }
     
        .insta-img {
                position: relative;
                z-index: 1;
        }

        .parallax {
            background-image: url('../assets/img/intro/visitback.jpg');
            background-repeat: no-repeat;
            position: fixed;
            z-index: 0;
            left: 0;
            opacity: .2;
            top:0px;
            background-position: 80px 0px;
            background-size: 100% 110vh;
            height: 100%;
            width: 100%;
}
.wrapper {
    position: relative;


}


.masonry {
    position: relative;
    // padding: 0;
    width: 90%;
    left: 5%;
    -moz-column-gap: 1.5em;
    -webkit-column-gap: 1.5em;
    column-gap: 1.5em;
    font-size: .85em;

}

.item {
    display: inline-block;
    position: relative;
    z-index: 1;
    margin-top: 20px;
         background: rgba(34, 34, 34, 0.576);
  
    
}


.centered{
    position: absolute;
    top: 50%;
    left: 50%;
     margin-right: -50%;
    transform: translate(-50%, -50%);
    font-size: 3vmin;
    font-weight: 500;
    // width: 100%;
    color: white;
    cursor: pointer;
    text-align: center;
    
}


@media only screen and (min-width: 300px) {
    .masonry {
        -moz-column-count: 2;
        -webkit-column-count: 2;
        column-count: 2;
    }
}

@media only screen and (min-width: 700px) {
    .masonry {
        -moz-column-count: 3;
        -webkit-column-count: 3;
        column-count: 3;
    }
}

@media only screen and (min-width: 900px) {
    .masonry {
        -moz-column-count: 4;
        -webkit-column-count: 4;
        column-count: 4;
    }
}

@media only screen and (min-width: 1024px) {
    .masonry {
        -moz-column-count: 3;
        -webkit-column-count: 3;
        column-count: 3;
    }
}

@media only screen and (min-width: 1280px) {
    .wrapper {
        // width: 1260px;
    }
}

        .v-img {
            
            max-height: 100%;
            max-width: 100%;
            filter: brightness(.7);
            transition: all .3s;
            
            cursor: pointer;
            z-index: 0;
            
        }
        .v-img:hover {
             filter: brightness(1);

        }
    }
  .modalImage {
        position: fixed;
            top: 0;
            left: 0;
            bottom: 0;
            right: 0;
            background: rgba(34, 34, 34, 0.8);
            z-index: 9;
  
  }

.modalImages {
    padding: 0;
    margin-top: 40px;
    // margin: 0 auto;
    
    

    img {
        max-height: 95%;
        top: 50%;
        left: 50%;
        position: absolute;
       transform: translate(-50%, -50%); 
      
   
    }

    .img-info {
        position: absolute;
        bottom: 0;
        left: 50%;
        margin-right: -50%;
        transform: translate(-50%, -50%);
        font-size: 2.5vmin;
        background: rgba(34, 34, 34, 0.479);
        padding: 10px 10px 0px; 
        color:white;
        display: inline;
    }

}

.closeImage {
    position: absolute;
    top: 10%;
    right: 5%;
    transform: translate(-50%, -50%);
    font-size: 70px;
    z-index: 9999;
    color:white;
    font-weight: 600;
    cursor: pointer;
}
    @media screen and (max-width: 1024px) {
              .parallax {
            background-image: url('../assets/img/intro/visitback.jpg');
            background-repeat: no-repeat;
            display: none;
            position: fixed;
            z-index: 0;
            left: 0;
            opacity: .2;
            top:0px;
            background-position: 0px 0px;
            background-size: 100% 110vh;
            height: 100%;
            width: 100%;
}
    }

    @media screen and (max-width: 748px) {
           #gallery {
        padding-top: 60px;
        }

          .v-img {
            opacity: 1!important;
              filter: blur(0px)!important;
              
        }

        .closeImage {
            font-size: 50px;
            top: 5%;
            right: 0%;
        }

                
        .modalImages {
            padding: 0;
            margin-top: 40px;
            // margin: 0 auto;
    

        img {
            // width: 50vw;
            max-width: 95%;
            top: 50%;
            left: 50%;
            position: absolute;
            transform: translate(-50%, -50%);
        
    
        }

            .img-info {
        position: absolute;
        bottom: 20%;
        left: 50%;
        margin-right: -50%;
        transform: translate(-50%, -50%);
        font-size: 2.5vmin;
        background: rgba(34, 34, 34, 0.479);
        padding: 10px 10px 0px; 
        color:white;
        display: inline;
    }

        }



    }
    

</style>



