<template>
  <div id="carousel">
      <div class="carousel">
           <v-carousel>
            <v-carousel-item v-for="(item,i) in items" :src="item.src" :key="i" :class="item.class"></v-carousel-item>
        </v-carousel>
      </div>
  </div>
</template>

<script>
export default {
  name: 'carousel',
   data(){
      return{
          slide: 0,
          sliding: null,
          items: [
              {src: "", class:"img"},
              {src:"", class:"dailyVersesWrapper "},
              {src:"", class:"dailyVersesWrapper2 "},
              {src:"", class:"dailyVersesWrapper3 "},
              {src:"", class:"dailyVersesWrapper4 "}
          ]
      }
  },
  methods: {
    onSlideStart (slide) {
      this.sliding = true
    },
    onSlideEnd (slide) {
      this.sliding = false
    },
      getVerses(){
          $(document).ready(function(){
          $.ajax({
               url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
               dataType: 'JSONP',
               success:function(json){
               $(".dailyVersesWrapper").prepend(json.html);
               
            }
            });
        $.ajax({
              url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
              dataType: 'JSONP',
              success:function(json){
               $(".dailyVersesWrapper2").prepend(json.html);
              }
           });
        $.ajax({
            url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
            dataType: 'JSONP',
            success:function(json){
             $(".dailyVersesWrapper3").prepend(json.html);
            }
         });
         $.ajax({
          url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
          dataType: 'JSONP',
          success:function(json){
           $(".dailyVersesWrapper4").prepend(json.html);
          }
        });
        $.ajax({
            url:'https://dailyverses.net/getrandomverse.ashx?language=es&isdirect=1&position=' + Math.floor(Math.random() * 201) + '&url=' + window.location.hostname,
            dataType: 'JSONP',
            success:function(json){
            $(".dailyVersesWrapper5").prepend(json.html);
            }
        });
          });
      }
},
    mounted(){
        this.getVerses()
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';

@import '../../assets/bootstrap.min';


.carousel {
    position: absolute;
    top: 0!important;
    left: 0;
    z-index: 99;
    height: 100vh;
}
.img {
    background: url("../../assets/img/intro/Intro-slide.png");
    background-size: 100%;
    background-position-y: 60%;
    background-position-x: -50px;
    background-repeat: no-repeat;
}

.dailyVersesWrapper, .dailyVersesWrapper2, .dailyVersesWrapper3, .dailyVersesWrapper4 {
    position: relative;
    width: 60%;
    text-align: center;
    color:white;
    font-weight: 500;
    font-size: 4vmin;
    top: 80%;
    left: 50%;
    margin-right: -50%;
    transform: translate(-50%, -50%);
  
}
    @media screen and (max-width: 1024px) {
        .carousel {
            height: 500px;
        }
        .img {
            background: url("../../assets/img/intro/Intro-slide.png");
            background-size: 100%;
            background-position-y: 60%;
            background-position-x: -30px;
            background-repeat: no-repeat;
        }
        .dailyVersesWrapper, .dailyVersesWrapper2, .dailyVersesWrapper3, .dailyVersesWrapper4 {
            position: relative;
            width: 60%;
            text-align: center;
            color:white;
            font-weight: 500;
            font-size: 3vmin;
            top: 80%;
            left: 50%;
            margin-right: -50%;
            transform: translate(-50%, -50%);
        
        }

    }

 @media screen and (max-width: 748px) {
         .carousel {
            height: 100vh;
        }
        .img {
            background: url("../../assets/img/intro/Intro-slide-mobile.png");
            background-size: 100%;
            // background-position-y: 60%;
            // background-position-x: -50px;
            background-repeat: no-repeat;
        }
            .dailyVersesWrapper, .dailyVersesWrapper2, .dailyVersesWrapper3, .dailyVersesWrapper4 {
            position: relative;
            width: 60%;
            text-align: center;
            color:white;
            font-weight: 500;
            font-size: 5vmin;
            top: 80%;
            left: 50%;
            margin-right: -50%;
            transform: translate(-50%, -50%);
        
        }


        }


</style>



