<template>
<div>
    <div id="main" style="color:white;"></div>
         <ul class="collection with-header">
         <!-- <ul class="collection with-header" v-for="(serie, index) in series" :key="index"> -->
        <li class="collection-header">
            <h4>Series</h4>
               <div class="fixed-action-btn" @click="modalAdd = true;">
                <a class="btn-floating btn-large">
                    <i class="fa fa-plus"></i>
                </a>
                </div>
                 <transition name="slideUp" >
                    <div class="modalEvent" id="addModal" v-if="modalAdd" >
                        <div class="modalContainer">
                            <div class="modalHeading">
                                <div class="close" @click="modalAdd = false; seriesUrl = null; newSeries.series_name = null; newSeries.series_des = null;">
                                    &times;
                                </div>
                                <div class="modalContent row">
                                    <div class="input-field col s6">
                                          <input type="text" v-model="newSeries.series_name">
                                          <label>Series Name</label>
                                        </div>
                                        <div class="input-field col s12">
                                          <input type="text" v-model="newSeries.series_des">
                                          <label>Series Description</label>
                                        </div>
                                    <div class="col s2">
                                       <button class="series-upload btn-floating btn-large" @click="pickImage()"><i class="fa fa-picture-o" aria-hidden="true"></i></button>
                                    <button v-if="seriesUrl" class="confirm-upload btn-floating btn-large" @click="createSeries(); imgUp == true;"><i class="fa fa-check" aria-hidden="true"></i></button>

                                        <input type="file" id="imageInput" style="display:none" accept="image/*" ref="imageInput" @change="AddImage">
                                        
                                    </div>
                                      <!-- <div class="col s12">
                                        <p style="margin-top: 30px;">File Preview:</p>
                                        <img :src="seriesUrl" alt="" style="width: 100%;"> 
                                    </div> -->
                                    <div class="row">
                                     
                                    <div class="col s11" style="margin-top: 50px;">
                                         <p>Card Preview:</p>
                                         <div class="row">
                                        <div class="col s10" style="margin-bottom: 10px;">
                                            <div >
                                                <a class="btn-floating btn-small" style="margin-right: 10px;" @click="imgZoom += 10;">
                                                        <i class="fa fa-search-plus" aria-hidden="true"></i>
                                                    </a>
                                                    <a class="btn-floating btn-small" @click="imgZoom -= 10; ">
                                                        <i class="fa fa-search-minus" aria-hidden="true"></i>
                                                    </a>
                                            </div>
                                         </div> 
                                        <div class="col s2" style="margin-bottom: 10px;">
                                            <div class="right">
                                                <a class="btn-floating btn-small" style="margin-right: 10px;" @click="imgPositionX -= 2;">
                                                        <i class="fa fa-arrow-left"></i>
                                                    </a>
                                                    <a class="btn-floating btn-small" @click="imgPositionX += 2; ">
                                                        <i class="fa fa-arrow-right"></i>
                                                    </a>
                                            </div>
                                         </div> 
                                        <div class="main-card z-depth-3 col s12">
                                            <div class="series-card">
                                                 <img class="center main-img" :src="seriesUrl" :style="{'top' : imgPositionY + '%', 'left' : imgPositionX + '%', 'width' : imgZoom + '%'}" alt="">
                                                <div class="main-title center">
                                                    {{newSeries.series_name}}
                                                </div>
                                                 <div class="main-arrow center"><i class="material-icons white--text medium">keyboard_arrow_down</i></div>
                                            </div>
                                        </div>
                                         </div>
                                    </div>
                                    <div class="col s1" style="margin-top: 120px;">
                                          <a class="btn-floating btn-small" style="margin-bottom: 10px;" @click="imgPositionY -= 8;">
                                                <i class="fa fa-arrow-up"></i>
                                            </a>
                                              <a class="btn-floating btn-small" @click="imgPositionY += 8; ">
                                                <i class="fa fa-arrow-down"></i>
                                            </a>
                                    </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                       

            </transition>
                
        </li>
            <div class="row">
                <div class="col s12 m4" v-for="(item, index) in series" :key="index">
                <div class="card" @click="getSeriesList(item.series_name); modal = true">
                    <div class="card-content white-text">
                    <span class="card-title">{{item.series_name}}</span>
                    </div>
                </div>
            </div>
                </div>

        <!-- <li class="collection-item" v-for="(item, index) in serie" :key="index">
          <div @click="getSeriesList(item); modal = true">{{item}}</div>
          </li> -->
      </ul>

      <transition name="slideUp" >
               <div class="modalEvent" id="addModal" v-if="modal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="modal = false; datavue.tempFiles = null; filesUploaded = true;">
                            &times;
                        </div>
                        <div class="modalContent">
                             <div>
                                   <!-- <div id="fileUp">File uploaded:</div> -->
                                 <div id="uploadProgress">
                                  <div id="bar" role="progressbar" aria-valuenow="0" aria-valuemin="0" aria-valuemax="100" style="width:2%"> <span id="perc">0%</span> </div>
                                </div>
                                <button class="upload" @click.once="pickFile()"><div v-show="filesUploaded"><i class="fa fa-cloud-upload fa-3x" aria-hidden="true"></i><br>Upload Audio Files</div> 
                                    <li class="item" v-for="(file, index) in datavue.tempFiles" :key="index"><p>{{file.name}} </p><i @click="deleteFile(file)" class="material-icons list-icons">delete</i></li>
                                    <button v-if="datavue.tempFiles" class="confirm-audio-upload btn-floating btn-large" @click=" datavue.tempList === ''; audioUpload(); "><i class="fa fa-check" aria-hidden="true"></i></button>
                                </button>
                                <input type="file" id="uploadedFile" multiple="multiple" accept="audio/*" style="display:none" ref="fileInput" @change="AddFile">
                            </div>
                            <div  class="audio-contain">
                                <div v-for="(item, index) in datavue.tempList" :key="index">
                                    <li class="audio-list">
                                        {{item}}
                                    </li>
                                </div>  
                            </div>
                         
                        </div>
                    </div>
                </div>
            </div>
    </transition>
<div id="snackbar" class="series z-depth-3">New Series Added!</div>
<div id="snackbar" class="files z-depth-3">Files Uploaded Successfully!</div>
<!-- <button @click="show()">click</button> -->
      <!-- <v-snackbar id="filesnack" :timeout="40000" top right multi-line v-model="fileUp">Files Uploaded Successfully! -->
        <!-- <v-btn flat color="cyan" @click.native="fileUp = false">Close</v-btn></v-snackbar> -->

  </div>

  

</template>

<script>

import {s3} from  '../../aws/aws-audio';
import {realDB} from  '../../firebase/firebase';


export default {
  name: 'dash-audio',
  data(){
      return {
        seriesUrl: '',
        seriesImg: '',
        imageName:'',
        filesUploaded: true,
        Imagefiles: '',
        imgUp: false,
        imgPositionY: 50,
        imgPositionX: 50,
        imgZoom: 110,
        fileUp: false,
        modal: false,
        progress: false,
        modalAdd: false,
        addItem: false,
        remove: '',
        folderName: '',
        datavue: {
            series: '',
            tempList: '',
            tempFiles: '' 
        },
        newSeries: {
            series_name : "",
            series_img: "",
            isActive : false,
            series_des: "",
            audio: []
        },
        series: []
      }
  },
  methods: {
      show(){
           $('#snackbar').toggleClass('show');                 

      },
    pickFile(){
        this.$refs.fileInput.click()
    }, 
    pickImage(){
        $('#imageInput').click()
    },
    getData(){
              var arr = [];
            realDB.ref('series').on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                                arr.push(child.val())
                            })
            })

            this.series = arr;
    },
    getSeriesList(folderName){

        this.folderName = folderName;

         var arr = [];

            realDB.ref('series').child(folderName).on(('value'), function(snapshot){

                var obj = snapshot.val().audio;
                 for(var val in obj) {
                         arr.push(obj[val].name.replace(/.mp3/g, ''))
                 }
        
            })

            this.datavue.tempList = arr;

            // console.log(this.datavue.tempList)

    },

    createSeries() {

        var newSeriesName = this.newSeries.series_name.replace(/ /g, "-")
        var newimageName = this.imageName.replace(/ /g, "-")
        

        realDB.ref("series").child(newSeriesName).set({
            series_name : newSeriesName,
            series_img: "https://s3.us-east-2.amazonaws.com/idcaudio/" + newSeriesName + '/' + newimageName,
            isActive: false,
            series_des: this.newSeries.series_des,
            data: [{name: "fill"}]

        })
 
        var SeriesKey = encodeURIComponent(newSeriesName) + '/';
            s3.putObject({Key: SeriesKey}, function(err, data) {
                // console.log(data)
           
            });

          
            var albumPhotosKey = encodeURIComponent(newSeriesName) + '/';
           
           let extn = newimageName.split('.').pop();

           var contentType;


            if (extn == 'png' || extn == 'jpg' || extn == 'gif') contentType = "image/" + extn;

            var photoKey = albumPhotosKey + newimageName;
            s3.upload({
                Key: photoKey,
                Body: this.Imagefiles,
                ContentType: contentType,
                ACL: 'public-read'
            }, function(err, data) {
                if (err) {
                return alert('There was an error uploading your photo: ', err.message);
                }
               
                $('.series').addClass('show')
            });
             setTimeout(function(){ $('.series').removeClass('show')}, 6000);
            this.modalAdd = false;

            this.getData()
            

        },
    AddImage(event){


            this.Imagefiles = event.target.files[0]
         
            this.imageName = this.Imagefiles.name;

            const fileReader = new FileReader()
            fileReader.addEventListener("load", () => {
                this.seriesUrl = fileReader.result;
            })
            fileReader.readAsDataURL(this.Imagefiles)



    },
    AddFile(event){

        this.audioUp = true;
        this.datavue.tempFiles = event.target.files;
        this.filesUploaded = false;

    },
    deleteFile(file){
        var newArr = [];

        newArr = Array.prototype.slice.call(this.datavue.tempFiles)

        var index = newArr.indexOf(file)

        if (index > -1) {
            newArr.splice(index, 1);
        }

        this.datavue.tempFiles = newArr;

    },
    audioUpload(){
        var files = this.datavue.tempFiles;


        var folderSeriesKey = encodeURIComponent(this.folderName) + '/';

            var seriesImg = this.seriesImg;

                var sizeTotal = 0;
                var loaded = [];
                var newFilesName = [];

            

        for (var i = 0; i < files.length; i++) {
                    sizeTotal += files[i].size;
                    loaded[files[i].name] = 0;
                    newFilesName.push(files[i].name);

                }

          for(var i= 0; i < files.length; i++){
    
                  realDB.ref("series").child(this.folderName).child('audio').push().set({
                        name: files[i].name,
                        url: folderSeriesKey + files[i].name,
                        seriesImg: seriesImg
                })
                                  
            s3.upload({
                Key: folderSeriesKey + files[i].name,
                Body: files[i],
                ContentType: "audio/*",
                ACL: 'public-read'
            }, 
            function(err, data) {
                if (err) {
                    console.log(err)
                return alert('There was an error uploading your photo: ', err.message);
                }
            }).on('httpUploadProgress', function(e) {

             loaded[this.body.name] = e.loaded;
                var loadedTotal = 0;
                for (var j in loaded) {
                    loadedTotal += loaded[j];
                }

                var progress = Math.round(loadedTotal / sizeTotal * 100);
                document.getElementById("bar").style.width = progress + '%'
                document.getElementById("perc").innerHTML = progress + '%';
               
                if (loadedTotal === sizeTotal) {
                    console.log("upload successful!")
                    $('.files').addClass('show')
                }
            });
            
          }  
            this.datavue.tempList = '';
            this.getData()
            setTimeout(function(){ $('.files').removeClass('show')}, 4000);  
    }
  
  },
  created(){
            var arr = [];
            realDB.ref('series').on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                                arr.push(child.val())
                            })
            })

            this.series = arr;

            console.log(this.series)
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/materialize.min.css';




.card {
  cursor: pointer;
  transition: all .3s ease-in-out;
  background: $gradient-dark-2;
  background-size: 150%;
  background-position-x: 40%;
}
.card:hover {
   transform: scale(1.05)
}

.modalEvent{
  position: fixed;
  // padding-top: 5vw;
  padding-left: 8vw;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  z-index: 99;
//   overflow-y: scroll;
  background: rgba(34, 34, 34, 0.741);
  
  .modalContainer {
     width: 80vw;
      margin: auto;
      margin-top: 2vh;
  }

  .modalHeading {
      padding: 6px;
      background: #222;
      color: white;
  }

  .modalContent {
      min-height: 90vh;
      padding: 44px;
      margin: 10px;
      background: rgba(0, 0, 0, 0.253);
      background-size: cover; 

      .collection-item:hover {
        background: #222;
        left: 0px;
      }
      
  }
  .close {
      padding: 10px 16px 0 0;
      color: white;
      font-size: 38px;
      z-index: 99;
      float: right;
      cursor: pointer;
    
      
  }
  .close:hover {
      transform: scale(1.4);
      transition: all .5s;
  }
}

.add-item {
  height: 225px;
}

.audio-contain {
    max-height: 300px;
    overflow-y: scroll;
}

/* width */
::-webkit-scrollbar {
    width: 10px;
}

/* Track */
::-webkit-scrollbar-track {
    background: #222; 
}
 
/* Handle */
::-webkit-scrollbar-thumb {
    background: $gradient-dark; 
    border-radius: 10px;
    // border: solid white 1px;
}

/* Handle on hover */
::-webkit-scrollbar-thumb:hover {
       background: $gradient-2;  
}


.audio-list {
    padding: 10px;

    border-bottom: solid rgb(87, 86, 86) 2px;
}


.series-upload {
    background: $gradient-2;



}
.confirm-upload {
    // position: ;
    background: $gradient-2;
    // float:right;
}
.confirm-audio-upload {
        background: $gradient-2;
        position: absolute;
        bottom: 10px;
        right: 10px;

}
#perc {
    font-size: 10px;
    top: -8px;
    position: relative;
}
#uploadProgress {
    width: 100%;
    background: $gradient-dark-2;
    margin-bottom: 10px;
    border-radius: 10px;

    #bar {
        width: 100%;
        height: 15px;
        background: $gradient-2;
        text-align: center;
        line-height: 30px;
        color: white;
        border-radius: 5px;

    }
}

.upload {
    position: relative;
    background: $gradient-dark-2;
    border-radius: 5px;
    width: 100%;
    min-height: 120px;
    max-height: 200px;
    overflow-y: scroll;
    border:none;
    font-size: 20px;
    margin-bottom: 20px;

    .item {
        background: rgba(34, 34, 34, 0.425);
        width: auto;
        font-size: 14px;
        padding: 10px;
        margin: 10px;
        display: inline-block;

        .list-icons {
            margin-left: 100px;
            // font-size: 14px;
        }
    }
  
  }

  
.collection {
  border:#222 2px solid;
}

.collection-header {
  background: #222!important;
  color:white;
  position: relative;
}

.collection .collection-item {
  // font-size: 1.6rem;
  color:white;
  background: rgb(82, 82, 82);
  height: 45px;
  left: 0;
  border:#222 2px solid;
  transition: all .3s ease-in-out;
}
.collection-item:hover {
   background: rgb(43, 40, 40);
   left: 10px;
   position: relative;
   cursor: pointer;
}


 .fixed-action-btn {
  position: absolute;
  z-index: 1;
  .btn-large {
    background: $gradient-dark;
    opacity: .8;
    transition: all .3s ease-in-out;
  }
  .btn-large:hover {
    opacity: 1;
  }
}


.main-card {
    background: #222;
    height: auto;
    width: auto;
    margin-bottom: 10px;
    border-radius: 5px;
    position: relative;
    overflow: hidden;
    cursor: pointer;

    .series-card {
        position: relative;
        height: 150px;
        opacity: .8;
        transition: opacity .2s ease-in-out;
    }
    .list-card {
        position: relative;
        max-height: 300px;
        overflow-y: scroll;
    }
    
    img {
        position: absolute;
        // width: 110%;
        // top: 50%;
    }
    .series-card:hover {
        opacity: 1;
    }

    .main-title {
        position: relative;
        font-size: 30px;
        color: white;
        left: 80%;
        top: 50%;
        text-align: left;

    }
    .main-arrow {
        position: absolute;
        left: 92%;
        top: 50%;
        
    }
}


      @media screen and (max-width: 1024px) {
          .card {

            .card-title {
                font-size: 1em;
            }

        }
      }

 

</style>



