<template>
  <div>
    <h4 class="header white-text" style="border-bottom: solid 2px white; padding-bottom: 30px;">Youtube Playlist</h4>
      <div style="position: absolute; top: 0px; right: 0px; z-index: 1;" @click="modalViAdd = true;">
                <a class="btn-floating btn-large add">
                    <i class="fa fa-plus"></i>
                </a>
                </div>
            


    <!-- add modal -->
        <transition name="slideRight">
               <div class="modalVideo" id="addModal" v-if="modalViAdd" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="modalViAdd = false; pdfFiles = ''; pdfName = ''; pdfUrl = ''">
                            &times;
                        </div>
                        <div class="modalContent">
                            <form @submit.prevent="addPlaylist" class="col s12">
                                      <div class="row">
                                          <div class="col s12">
                                              <h3>Add Playlist: <strong style="text-decoration: underline;">{{videoNew.name}}</strong></h3>
                                          </div>
                                        <div class="input-field col s4">
                                          Name : <input type="text" v-model="videoNew.name" required>
                                          <!-- <label>Name</label> -->
                                        </div>
                                         <div class="input-field col s6">
                                          Playlist Link : <input type="text" v-model="videoNew.playlist" required>
                                          <!-- <label>Playlist Link</label> -->
                                        </div>
                                        <div class="input-field col s12">
                                          Description: <input type="text" v-model="videoNew.des" required>
                                          <!-- <label>Playlist Link</label> -->
                                        </div>
                                        <button class="pdf-upload btn-floating btn-large" @click="pickFile()"><i class="material-icons pdf">picture_as_pdf</i></button>
                                        <input type="file" id="pdfInput" style="display:none" accept="application/pdf" ref="fileInput" @change="AddPdf">

                                           <div class="col s12">
                                                <p style="margin-top: 30px;">File Preview: <strong style="font-size:20px;"> {{pdfName}}</strong></p>
                                                    <pdf
                                                        v-for="i in numPages"
                                                        :key="i"
                                                        :src="loadingTask"
                                                        :page="i"
                                                        style="display: inline-block; width: 25%"
                                                    ></pdf>

                                                <!-- <img :src="pdfUrl" alt="" style="width: 100%;">  -->
                                            </div>
                                      </div>
                                      <div class="confirm-btn row right" style="top: -25px; margin: 0px;">
                                          <div class="col s5"><a class="waves-effect waves-light btn-floating btn-large hoverable" style="margin: 0px;" @click="addPlaylist()"><i class="material-icons yes">check</i></a></div>                                      
                                          <div class="col s5"><a class="waves-effect waves-light btn-floating btn-large hoverable" style="margin: 0px;" @click="onCancel()"><i class="material-icons no">clear</i></a></div>  
                                      </div>
                                   </form>
                        </div>
                    </div>
                </div>
            </div>
    </transition>
      <div class="row">
        <div class="col s12 m4" v-for="(item, index) in video" :key="index">
         <div class="card hoverable">
            <div class="card-content white-text">
             <span class="card-title" style="margin-top: 10px;">{{item.name}}</span>
             <div @click="editVideo(item); modalVi = true;">
                  <a class="btn-floating delete z-depth-1 hoverable" style="background: linear-gradient(90deg, rgba(180,58,58,0.8211659663865546) 0%, rgba(236,79,79,1) 100%);">
                    <i class="material-icons no">clear</i>
                </a>
             </div>
            </div>
        </div>
     </div>
    </div>

<!-- edit modal -->
    <transition name="zoom">
               <div class="modalDelete" id="editModal" v-if="modalVi">
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="modalVi = false; ">
                            &times;
                        </div>
                        <div class="modalContent row">
                                    <div class="col s10 offset-s1">
                                        <h4>Are you sure you want to delete <strong style="text-decoration: underline;">{{videoSel.name}}</strong> ?</h4>
                                    </div>
                                      <div class="confirm-btn col s10 offset-s4">
                                          <div><a class="waves-effect waves-light btn-large btn-floating hoverable" style="background: #222;" @click="deletePlaylist()"><i class="material-icons yes">check</i></a></div>                                      
                                          <div><a class="waves-effect waves-light btn-large btn-floating hoverable" style="background: #222;" @click="onCancel()"><i class="material-icons no">clear</i></a></div>  
                                      </div>
                                
                        </div>
                    </div>
                </div>
            </div>
    </transition>

    <div id="snackbar" class="video z-depth-3">New Playlist Added!</div>
    <div id="snackbar" class="deletesnack z-depth-3">Playlist Deleted!</div>

  </div>
</template>

<script>
import {realDB} from  '../../firebase/firebase';
import pdf from 'vue-pdf'
import {s3} from  '../../aws/aws-video';


export default {
 name: 'dash-video',
  components: {
    pdf
  },
 data(){
     return {
         video: '',
         videoSel: '',
         videoNew: {
            name: '',
            playlist: '',
            des: ''
            },
         modalVi: false,
         modalViAdd: false,
         pdfFiles: '',
         pdfName: '',
         pdfUrl: '',
         loadingTask: '',
        //  src: loadingTask,
		numPages: undefined,
         currentPage: 0,
         pageCount: 0,

     }
 },
 methods: {

     getData(){
          var arr = [];
 
                realDB.ref('videos').on(('value'), function(snapshot){
                            snapshot.forEach(function(child){
                                arr.push(child.val())
                            })
                        
                        })
                this.video = arr;  
     },
     onCancel(){
         this.modalVi = false;
         this.modalViAdd = false;
         this.pdfFiles = ''; 
         this.pdfName = '';
        //  this.loadingTask = ''
     },
     editVideo(item){

         console.log(item)

         this.videoSel = item;

         if(!item.url) {
             this.loadingTask = pdf.createLoadingTask(item.url)
             this.loadingTask.then(pdf => {
                            this.numPages = pdf.numPages;
                        });
        }
                 
     },
          pickFile(){
            this.$refs.fileInput.click()
    }, 
        // replaceFile(){
        //       $('#pdfReplace').click()

        // },
        AddPdf(event){

                // console.log(event.target.files)
            this.pdfFiles = event.target.files[0]
            var tmppath = URL.createObjectURL(this.pdfFiles);
         
            this.pdfName = this.pdfFiles.name;

            this.loadingTask = pdf.createLoadingTask(tmppath);


            this.loadingTask.then(pdf => {

            this.numPages = pdf.numPages;
                        });

        },

    addPlaylist(){

          this.video = [];
        
        var newPlaylistName = this.videoNew.name.replace(/ /g, "-")

        var pdfName = this.pdfName.replace(/ /g, "-")
        

        realDB.ref("videos").child(newPlaylistName).set({
            active: false,
            des: this.videoNew.des,
            name: this.videoNew.name,
            playlist: this.videoNew.playlist,
            url: "https://s3.us-east-2.amazonaws.com/idcvideo/" + newPlaylistName + '/' + pdfName

        })

      
            

 
        var PlayKey = encodeURIComponent(newPlaylistName) + '/';
            s3.putObject({Key: PlayKey, ACL: 'public-read-write'}, function(err, data) {
           
            });

            var videoKey = encodeURIComponent(newPlaylistName) + '/';
           
           let extn = pdfName.split('.').pop();

           var contentType;

            if (extn == 'pdf' ) contentType = "application/" + extn;

            var video = videoKey + pdfName;

            if(this.pdfFiles) {
                 s3.upload({
                Key: video,
                Body: this.pdfFiles,
                ContentType: contentType,
                ACL: 'public-read'
                }, function(err, data) {
                    if (err) {
                    return alert('There was an error uploading your photo: ', err.message);
                    }
            
                });
            }


            this.modalViAdd = false;
    
            $('.video').addClass('show')
             setTimeout(function(){ $('.video').removeClass('show')}, 6000);

               this.getData()

          
    },

    deletePlaylist(){
        var Name = this.videoSel.name.replace(/ /g, "-")

         realDB.ref("videos").child(Name).remove()

              var videoKey = encodeURIComponent(Name) + '/';


                s3.listObjects({Prefix: videoKey}, function(err, data) {
                
                    var objects = data.Contents.map(function(object) {
                    return {Key: object.Key};
                    });

                    s3.deleteObjects({
                    Delete: {Objects: objects, Quiet: true}
                    }, function(err, data) {

                        console.log(err)
                        console.log(data)
                  
                    });
                });
    


            $('.deletesnack').addClass('show')
             setTimeout(function(){ $('.deletesnack').removeClass('show')}, 6000);
            this.modalVi = false;

              this.getData()
    }
     },
 created(){
    var arr = [];
 
    realDB.ref('videos').on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                    arr.push(child.val())
                })
               
            })
    this.video = arr;  
   
 }
}
</script>

<style  lang="scss" scoped>

@import '../../assets/main';
@import '../../assets/materialize.min.css';

.card {
  cursor: pointer;
  transition: all .3s ease-in-out;
  background: $gradient-dark-2;
  min-height: 130px;
  background-size: 150%;
  background-position-x: 40%;
    .card-title {
        font-size: 2em;
    }

}

.delete {
    position: absolute;
    top: -10px;
    right: -10px;
    transition: all .3s;
    z-index: 1;
}
// .delete:hover {
//     transform: rotate(90deg);
// }
// .card:hover {
//    transform: scale(1.05)
// }
.add, .pdf-upload {
     background: $gradient-dark;
}

.confirm-btn{
  position: relative;   
  display: inline-flex;
  margin: 10px;

      .btn-floating {
          margin: 20px;
          left: 20px;
          position: relative;
          background:$gradient-dark;
      
    }
}



.modalVideo{
  position: fixed;
  padding-top: 1vw;
  padding-left: 8vw;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  z-index: 9;
  background: rgba(34, 34, 34, 0.741);
  overflow-y: scroll;
  
  .modalContainer {
     width: 80vw;
      margin: auto;
      margin-top: 2vh;
  }

  .modalHeading {
      padding: 6px;
      background: #222;
      color: white;
  }

  .modalContent {
      min-height: 40vh;
      padding: 44px;
      margin: 10px;
      background: rgba(0, 0, 0, 0.253);
      background-size: cover; 

      .collection-item:hover {
        background: #222;
        left: 0px;
      }
      
  }
}

.modalDelete{
  position: fixed;
  padding-top: 10vw;
  padding-left: 8vw;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  z-index: 9;
  background: rgba(34, 34, 34, 0);
//   overflow-y: scroll;
  
  .modalContainer {
     width: 80vw;
      margin: auto;
      margin-top: 2vh;
  }

  .modalHeading {
      padding: 5px;
      background: $gradient-dark-2;
      color: white;
  }

  .modalContent {
      height: 270px;
      padding-top: 44px;
      margin: 10px;
      background: $gradient-dark;
      background-size: cover; 

   
      
  }

}

  .close {
      padding: 10px 16px 0 0;
      color: white;
      font-size: 38px;
      z-index: 99;
      float: right;
      cursor: pointer;
    
      
  }
  .close:hover {
      transform: scale(1.4);
      transition: all .5s;
  }

      @media screen and (max-width: 1024px) {
          .card {

    .card-title {
        font-size: 1em;
    }

}
      }


</style>



