    background: $gradient-dark;
    position: relative;
    display: block;

}
a {
    color:white;
}
.left {
  left: 35%;
  position: relative;
}
.img {
    width: 100px;
}

@media screen and (min-width: 768px) {
    
 }

@media screen and (max-width: 748px) {
    .left {
      left: 10%;
      margin-right: 40px;
    }

    .foot {
      left:-20px;
      position: relative;
    }



}

</style>



