<template>
  <div id="mission" class="slideshow-container">
         <div class="mexico fade">
              <div> <button class="z-depth-2 center hoverable" @click="showingModal = true;">INFORMACION</button></div>

             <transition name="slide-fade">
                <div class="modall " id="addModal" v-if="showingModal" >
                    <div class="modalContainer z-depth-3">
                        <div class="modalHeading">
                            <div class="close" @click="showingModal = false;">
                                &times;
                            </div>
                            <div class="modalContent">
                                <div class="row">
                                    <div class="text col s6">
                                        <h4>{{missions[0].title}}</h4>
                                        <p>{{missions[0].text}}</p>
                                    </div>
                                <div class="money col s6">
                                    <span>$</span>
                                <i-count-up
                                    :startVal="0"
                                    :endVal= missions[0].count
                                    :decimals="0"
                                    :duration="2" 
                                    :options="options" 
                                    @ready="onReady"
                                    ></i-count-up>
                                </div>
                                </div>   
                            </div>
                        </div>
                    </div>
                </div>
                </transition>
         </div>
  </div>
</template>

<script>

import ICountUp from 'vue-countup-v2'
import db from  '../../firebase/firebase'



export default {
  name: 'mission',
  data(){
      return {
            showingModal: false,
            options: {
            useEasing: true,
            useGrouping: true,
            separator: ',',
            decimal: '.',
            prefix: '',
            suffix: '',
           
        },
         missions: []

      }
  },
  components: {
      ICountUp
  },
  created(){

    db.collection('MissionData').get().then 
    (querySnapshot => {
      querySnapshot.forEach(doc => {
        const data = {
          'id': doc.id,
          'count': doc.data().count,
          'title': doc.data().title,
          'text': doc.data().text
        }
        this.missions.push(data)
        console.log(this.missions)
      })
    })
  },
  methods: {
        onReady: function(instance, CountUp) {
        const that = this;
        instance.update(that.endVal + 100);
      },
  },
  mounted(){
  }

  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';
// @import '../../assets/bootstrap.min';
@import '../../assets/materialize.min.css';

#mission {
    height: 100vh;
    position: relative;

}
.mexico {
    height: 100vh;
    position: relative;
    background-image: url('../../assets/img/intro/mission.png');
    background-size: 100%;
    background-position: -10% 100%;
    background-repeat: no-repeat;
    
}


img {
    width: 100%;
    position: relative;

}
button {
    position: absolute;
    top:75vh;
    left: 47%;
    color:white;
    background: $gradient-2;
    padding: 20px;
    font-size: 1.5em;
    border-radius: 5px;
}
.money {
    font-size: 6vw;
    padding: 30px auto;
}
.modall {
    padding-top: 0vh;
}
.modalContent {
    height: 85vh;
}

@media screen and (max-width: 1024px) {
    #mission {
    height: auto;
    position: relative;

}
.mexico {
    height: 40vh;
  
    
}

button {
    position: absolute;
    top:33vh;
}


}

@media screen and (max-width: 748px) {

.mexico {
    height: 100vh;
    position: relative;
    background-image: url('../../assets/img/intro/mission-mobile.png');
    background-size: 100%;
    background-position: -10% 100%;
    background-repeat: no-repeat;
    
}

button {
    position: absolute;
    top:80vh;
}


}


</style>



