<template>
  <div id="series">
      
       <loader v-if="loading"/>
       <div v-show="loading === false">
         <div id="content"> 
             <div class="row">
                  <div class="col s12 m6 main-list">
                        <div id="mylist" class="list">
                            <div id="songs">        
                                <input type="text" class="center z-depth-3" id="myInput" autocapitalize="none"  v-model="search" placeholder="Buscar..." style="height:10px; margin-top:50px;">
                             </div>    
                        <div class="white--text" v-for="(serie, index) in searchList" :key="index" >
                                  <div class="col s12">
                                        <div class="main-card z-depth-3" >
                                            <div class="series-card" >
                                                 <img class="center main-img" :src="serie.series_img" alt="">
                                                <div class="main-title center">
                                                    {{serie.series_name.replace(/-/g, " ")}}
                                                </div>
                                                 <div class="main-arrow center" v-if ="!serie.isActive"  @click="toggleCardOn(serie);"><i class="fa fa-chevron-circle-down fa-3x" aria-hidden="true"></i></div>
                                                 <div class="main-arrow center" v-if="serie.isActive" @click="toggleOff(serie)"><i class="fa fa-chevron-circle-up fa-3x" aria-hidden="true"></i></div>
                                            </div>

                                          <transition name="fadeHeight" mode="out-in">
                                            <div class="list-card" v-show="serie.isActive">
                                                <div class="collection">
                                                <li class="collection-item" v-for="(audio, index) in serie.audio" :key="index" :id="audio.url" :value="audio.url" @click="playAudio(audio, index, serie); " > 
                                                 <!-- <a :href="Audio.src" class="btn-floating waves-effect waves-light white" download><i class="material-icons">audiotrack</i></a><p class="truncate para" >| {{audio.name}}</p> -->
                                                 <a :href="Audio.src" class="btn-floating waves-effect waves-light white" download><i class="material-icons">audiotrack</i></a><p class="truncate para" >| {{audio.name.replace(/.mp3/g, "")}}</p>
                                                
                                               </li> 
                                               
                                                </div>
                                            </div>
                                          </transition>
                                        </div>
                                    </div>
                                </div>                                 
                        </div>
                </div>
                 

                <div class="col s12 m6 right-pane" style="position: fixed; right: 0; bottom: 0; width:45%; height:100vh;"> 
                            <transition name="slide-fade">
                      <div class="row">
                        <div class="col s12 hide-on-small-only">
                        <div class="card">
                            <div class="card-image">
                                <div class="volume-icons"><i class="material-icons">volume_up</i>
                                <i class="material-icons">volume_down</i></div>
                                <div class="volume-div"><input class="volume" type="range" min="0" max="100" :value="volume" orient="vertical" step="1" @input="volumeChange"></div>
                                <img  :src="audio.currSerieImg" >
                                <div class="card-serie center">{{audio.currentSerie.replace(/-/g, " ")}}</div>
                            <span class="card-title truncate">{{audio.currentTrack}}</span>
                            <a :href="Audio.src" class="btn-floating halfway-fab waves-effect waves-light back-gradient" download><i class="material-icons">audiotrack</i></a>
                            </div>
                            <div class="card-content">
                            <p>{{audio.currentDes}}</p>
                            </div>
                        </div>
                        </div>
                    </div>            
                            </transition>
                      
                <div class="seek"><input id="seekslider" type="range" min="0" max="100" :value="value" step="1" @input="seeking"></div>

                <div id="controls" style="position:fixed;">
                              <!-- <double-bounce  class="center"></double-bounce> -->
                    <div v-show="audioLoaded" ><stretch class="loader"></stretch></div>

                    <div v-show="!audioLoaded"><h1 id="curtrack" class="text-gradient truncate">{{audio.currentTrack}}</h1></div>
                    
                    <div v-show="!audioLoaded" id="timebox"><span @change="audioLoaded === false">{{time}} / {{endtime}}</span></div>


                <div class="audio_player col xs12">
                    <div class="row all-buttons center">
                       
                        <a class="btn-floating waves-effect waves-light hoverable col xs2" @click="prevTrack()" style="top: 7px;"><i class="fa control-buttons fa-backward" style="margin-left: -12px; font-size: 15px;"></i></a>
                        <a class="btn-floating btn-large waves-effect waves-light hoverable col xs2" >
                            <i @click="pauseAudio()" v-if="playing === true" class="fa control-buttons fa-pause" style="margin-left: 0px;"></i>
                            <i @click="resumeAudio()" class="fa control-buttons fa-play" v-else></i>
                        </a>
                        <a class="btn-floating waves-effect waves-light hoverable col xs2" @click="nextTrack()" style="top: 7px;"><i class="fa control-buttons fa-forward" style="margin-left: -7px; font-size: 15px;"></i></a>                        
    
                   </div>
                   <div>
                         <a class="btn-floating waves-effect waves-light hoverable col xs2 mute-btn" >
                            <i @click="Audio.muted = false; mute = false" v-if="mute == true" class="material-icons" style="margin-left: -12px; font-size: 25px;">volume_up</i>
                            <i @click="Audio.muted = true; mute = true" v-else class="material-icons" style="margin-left: -12px; font-size: 25px;">volume_off</i>
                    </a> 
                   </div>
                 
                </div>
                </div> 
            </div>
            </div>
         </div>
       </div>
 
  </div>
</template>

<script>

import json from '../../assets/audio/audio.json';
import Loader from '../main/Loader.vue';
import axios from 'axios';

import {realDB} from  '../../firebase/firebase';
import {s3} from  '../../aws/aws-audio';
import {DoubleBounce, Stretch} from 'vue-loading-spinner'
import GetSheetDone from 'get-sheet-done'

export default {
  name: 'series',
  components: {
    "loader": Loader,
      DoubleBounce,
      Stretch
    
  },
  data(){
      return {
          data: [],
          series: [],
          audioList:[],
          search: '',
          loading: false,
          audioLoaded: true,
          playing: false,
          mute:false,
          currentSerieSel: [],
          Audio:'',
          const: {
            amz: "https://s3.us-east-2.amazonaws.com/idcaudio/"
          },
          audio: {
              index: '',
              url:'',
              currentSerie: '',
              currSerieImg: require('../../assets/img/series/audio-cover.png'),
              currentDes: 'Descripcion de Serie',
              serieLength: '',
              currentTrack: "Escoje un Audio...",
              des: ''
          },
          time: "00:00",
          endtime: "00:00",
          value: "0",
          volume: '100'
      }
  },
    methods: {

        toggleOff(serie){
            serie.isActive = false;
        },

      toggleCardOn(serie){
          this.currentSerieSel = [];
          serie.isActive = true;

          for (var audio in serie.audio) {
                this.currentSerieSel.push(serie.audio[audio])
                }

          console.log(this.currentSerieSel)
    

      },
      newAudio(){

            this.Audio = new Audio();

          

             this.Audio.addEventListener("timeupdate", this.seekUpdate);
      },
      playAudio(track , index, serie){

        this.audioLoaded = true; 
          
            this.Audio.src = this.const.amz + track.url;
            console.log(track.url)
            //  track.isPlaying = false;
            this.playing = true;
            this.Audio.play();

            this.audio.currentTrack = track.name.replace(/.mp3/g, "");
            this.audio.currentSerie = serie.series_name;
            this.audio.currentDes = serie.series_des;
            this.audio.url = track.url;
            this.audio.currSerieImg = serie.series_img;
            this.audio.image = track.image;
            this.audio.des = track.des;

        

      },
      pauseAudio(){
             this.playing = false;
            this.Audio.pause();
      },
      resumeAudio(){
             this.playing = true;
            this.Audio.play();
      },
      ////TRY OUT PREV AND NEXT BUTTONS WHEN DATA ADDED!
      nextTrack(){

          
        
        var trackUrl = document.getElementById(this.audio.url);
            var trackname = $(trackUrl).next().attr('value')

             if(trackname === undefined) {

                    this.Audio.src = this.const.amz + $(trackUrl).attr('value')
                    this.audio.currentTrack = $(trackUrl).children('p').text()
                    this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);

                    this.Audio.play();

                    this.audio.url = $(trackUrl).attr('value');
                
            } else {
            this.Audio.src = this.const.amz + $(trackUrl).next().attr('value')
            this.audio.currentTrack = $(trackUrl).next().children('p').text()
            this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);
            this.Audio.play();

            this.audio.url = $(trackUrl).next().attr('value');
            }

           
        
    
      },
      prevTrack(){
        
        var trackUrl = document.getElementById(this.audio.url);
          var trackname = $(trackUrl).prev().attr('value')

           if(trackname === undefined) { 
                    this.Audio.src = this.const.amz + $(trackUrl).attr('value')
                    this.audio.currentTrack = $(trackUrl).children('p').text()
                    this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);
                    this.Audio.play();
                    this.audio.url = $(trackUrl).attr('value');
           
           } else {
            this.Audio.src = this.const.amz + $(trackUrl).prev().attr('value')
            this.audio.currentTrack = $(trackUrl).prev().children('p').text()
            this.audio.currentTrack = this.audio.currentTrack.substring(this.audio.currentTrack.indexOf("|") + 1);
            this.Audio.play();

            this.audio.url = $(trackUrl).prev().attr('value'); 
           }

            
        
      },
      seekUpdate(){

        //   console.log(this.Audio.duration)


           
        var nt = this.Audio.currentTime * (100 / this.Audio.duration)
      
       this.value = nt;
      
       var curhrs = Math.floor(this.Audio.currentTime / 3600);
       var curmins = Math.floor(this.Audio.currentTime / 60);
       var cursecs = Math.floor(this.Audio.currentTime - curmins * 60);

       var durhrs = Math.floor(this.Audio.duration / 3600);
       var durmins = Math.floor(this.Audio.duration / 60);
       var dursecs = Math.floor(this.Audio.duration - durmins * 60);

         if(durhrs > 0){
            durmins = durmins % 60;
            curmins = curmins % 60;
        }
       
        if(cursecs < 10){ cursecs = "0" + cursecs; }
        if(curmins < 10){ curmins = "0"+ curmins; }
      

        if(dursecs < 10){ dursecs = "0"+ dursecs; }
        if(durmins < 10){ durmins = "0"+ durmins; }

        
        if(durhrs == 0){ 
              this.time = curmins+":"+cursecs;
               this.endtime = durmins+":"+dursecs;

        } else {
            this.time = curhrs+":"+curmins+":"+cursecs;
            this.endtime = durhrs+":"+durmins+":"+dursecs;
        }

      
    
            

            // console.log(nt)

        
      },
      seeking(event){
            
            var seekto = this.Audio.duration * (event.target.value / 100);  

            this.Audio.currentTime = seekto;     
        },
        volumeChange(event){

            this.Audio.volume = event.target.value / 100;
            this.volume = event.target.value;

        }
    },
    computed:{
        searchList: function(){
            return this.series.filter((serie) => {
                return serie.series_name.toLowerCase().match(this.search);
            })
        },
        sortList: function(){
            var audio = this.currentSerieSel;

            // audio.push(this.currentSerieSel)

            // this.currentSerieSel.forEach(val => {
            //     audio.push(val)
            // })
            // console.log(audio)
            return audio.sort(function(a, b){
                    if(a.name < b.name) return -1;
                    if(a.name > b.name) return 1;
                    return 0;
        })
        },
       
        loadS3(){
             var sArr = [];
        s3.listObjects({Delimiter: '/'}, function(err, data) {

                    if (err) {
                    return alert('There was an error listing your albums: ' + err.message);

                    } else {

                            
                        var albums = data.CommonPrefixes.map(function(commonPrefix) {
                                    var prefix = commonPrefix.Prefix;
                                    var albumName = decodeURIComponent(prefix.replace('/', ''));
                                    return albumName;
                                });

                                    sArr.push(albums);
                            
                        }
                                    

                    });

        }
    },
    mounted(){
        this.newAudio()
        // this.seeking()
  },
  watch: {
          time: function (val) {
            this.audioLoaded = false;
          }
  },
  created(){
    //   var url = 'https://sheets.googleapis.com/v4/spreadsheets/1kZX_tAhb9iHGogndPXbwdtmwrIJTRRQjmzCtCvY_EXI/values/data?valueRenderOption=FORMATTED_VALUE&key={YOUR_API_KEY}';


           axios.get('https://sheets.googleapis.com/v4/spreadsheets/1kZX_tAhb9iHGogndPXbwdtmwrIJTRRQjmzCtCvY_EXI/values/data?valueRenderOption=FORMATTED_VALUE&key=AIzaSyB0rs_uG0aQBeCLlXUILdqOlbpOFBVjEYc').then(response => {
               console.log(response);
           })
// var $url = 'https://cors-anywhere.herokuapp.com/https://spreadsheets.google.com/feeds/list/2PACX-1vRM7y32Qvw_4Yruqi2zsY8bNlQBDNsthxY0MFPy2GcMqd1xecjGaX0W4OBYBTIU2CGtBbwUR4CdAq9S/od6/public/value?alt=json';
// $.getJSON($url,function(data){
//     alert(JSON.stringify(data.feed.entry));
// });

    // GetSheetDone.raw("1vRM7y32Qvw_4Yruqi2zsY8bNlQBDNsthxY0MFPy2GcMqd1xecjGaX0W4OBYBTIU2CGtBbwUR4CdAq9S", 1, false, true).then(sheet => console.log(sheet))

      this.series = null;

          var arr = [];

          

            realDB.ref('series').on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                    arr.push(child.val())

                    
                })
               
            })
            this.series = arr;

            this.loading = false;

        

  }
}
</script>

