<template>
  <div>

    <scrollactive class="my-nav" ref="scrollactive" :offset="0"
      :duration="800"
      bezier-easing-value=".5,0,.35,1">
      <a href="#intro" class="scrollactive-item">Intro</a><br>
      <a href="#welcome" class="scrollactive-item">Bienvenida</a><br>
      <a href="#topics" class="scrollactive-item">Horario</a><br>
      <a href="#social-media" class="scrollactive-item">Medios</a><br>
      <a href="#evang" class="scrollactive-item">Evangelio</a><br>
      <a href="#plan" class="scrollactive-item">PlanDeDios</a> <br>     
      <a href="#preacher" class="scrollactive-item">Predicador</a><br>
      <a href="#mission" class="scrollactive-item">Missiones</a><br>
      <a href="#team" class="scrollactive-item">Equipo</a><br>
      <a href="#groups" class="scrollactive-item">Groupos</a>

  </scrollactive>
  </div>
</template>

<script>

export default {
  name: 'scrollspy'
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../../assets/main.scss';


// fixed side navigation with dots
.my-nav{
  position: fixed;
  
  // bottom:0px;
  bottom: 40vh;
  border-radius: 10px;
  right: -10px;
  width: 90px;
  z-index: 99999;
  text-align: center;
  transition: all .3s;
  background: rgba(87, 86, 86, 0.885);


  a{
    text-decoration: none;
    font-size: .7vw;
    color: white;
    
  }
  a:hover {
    font-weight: 500;
  }

  .is-active {
    position: relative;
    font-weight: 700;
    line-height: 35px;
}
  
}

.my-nav:hover {

}

</style>



