<template>
     <div id="topic">
         <div class="parallax visible-lg"></div>
        <!-- <img class="img-title center" src="../../assets/img/texts/dias.png" alt=""><br> -->
            
            <div class="wrapper row">
                <div class="boxes col s12 m6">
                             <div class="parallax-mobile hidden-xs hidden-lg"></div>
                     <h1 class="hidden-xs">DIAS<br> DE<br> REUNION</h1>
                     <h1 class="visible-xs">DIAS DE REUNION</h1>
                </div>
                <div class="mobile col s12 m6">
                    <div class="card col m5 hoverable hidden-xs" v-for="(day, index) in days" :key="index" @click="clickedDay(day); showingModal = true;">
                        <div class="day center ">
                            <h2>{{day.text}}</h2>
                            <!-- <img :src="day.img"><br> -->
                                <!-- <div class="divider"></div><br> -->
                            <h4>{{day.time}}</h4>
                        </div>
                    </div>
                    <div class="row visible-xs"> 
                     <div class="card col s5 hoverable " v-for="(day, index) in days" :key="index" @click="clickedDay(day); showingModal = true;">
                            <h5>{{day.text}}</h5>
                            <p>{{day.time}}</p>
                    </div>
                    </div>
                </div>
             

        <transition name="slide-right">
               <div class="modal2" id="addModal" v-if="showingModal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="showingModal = false;">
                            &times;
                        </div>
                        
                        <div class="modalContent">
                            <div class="mcback" :style="{ 'background-image': 'url(' + fireData.url + ')'}"></div>
                            <div class="mctext">
                                 <h2>{{fireData.day.replace(/-/g, ' ')}}</h2>
                                <h3>{{fireData.topic_name}}</h3>
                                <p>{{fireData.topic_des}}</p>
                            </div>
                               
                        </div>
                    </div>
                </div>
            </div>
            </transition>
             
            </div>

     
        
     </div>
</template>

<script>
import {realDB} from  '../../firebase/firebase';


export default {
  name: 'topics',
  data(){
      return {
          days: [
              {time: '7-8 PM', dayImg: 'https://source.unsplash.com/lLk1oJA7kg', text: "Lunes", day: "", details: ""},
              {time: '7-8 PM', dayImg: 'https://source.unsplash.com/lLk1oJA7Wkg', text: "Miercoles", day: "Current Series", details: " Brief description of series"},
              {time: '9:30-11 AM', dayImg: 'https://source.unsplash.com/YS3Q5vroxtg', text: "Domingo AM", day: "Current Series", details: " Brief description of series"},
              {time: '3-4 PM' ,dayImg: 'https://source.unsplash.com/t1QUoAMyXDs', text: "Domingo PM", day: "Current Series", details: " Brief description of series"},
            ],
            dayClicked: {},
            fireData: null,
            showingModal: false,
            daysTopic: [],

      }
  },
  methods: {
      clickedDay(day){
        
        day.text = day.text.replace(/ /g, "-")

           for(var prop in this.daysTopic) {
            // console.log(prop + ': ' + this.daysTopic[prop].day);
         
            if(this.daysTopic[prop].day == day.text) {
                    this.fireData = this.daysTopic[prop]
                    console.log(this.fireData);

            }
        }

      }
  },
  mounted(){
  },
  created(){
            var arr = []
                realDB.ref('topics').orderByChild("id").on(('value'), function(snapshot){
                  snapshot.forEach(function(child){
                    arr.push(child.val())
                })
            })

            // console.log(arr)

              this.daysTopic = arr;
        console.log(this.daysTopic)
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';
@import '../../assets/bootstrap.min';
@import '../../assets/materialize.min.css';


#topic {
    background: #222;
    height: 100vh;
    position: relative;

}
.wrapper {
    height: 100vh;
    position: relative;

}

h1 {
  position: relative;
  color: #fff;
  opacity: 1;
  font-size: 7.5vw;
  text-align: left;
  font-weight: 400;
  z-index: 0;
  left: 50px;
  top: 10vh;
}
.parallax {
    background-image: url('../../assets/img/intro/visitback.jpg');
    background-repeat: no-repeat;
    position: absolute;
    z-index: 0;
    left: 0;
    opacity: .2;
    background-attachment: fixed;
    background-position: 80px 0px;
    background-size: 100% auto;
    height: 100%;
    width: 100%;
}

.card {
    height: 200px;
    cursor: pointer;
    margin-left: 10px!important;
    top: 5vw;
    position: relative;
}


    .day {
        text-align: center;
        position: relative;
        top: 60px;
        color: #222;
        transition: all 1s;
        // background: linear-gradient(90deg, rgb(46, 89, 102)  0%, rgb(92, 173, 201) 95%,  #d46e6e 5%);
        
        h2 {
            font-size: 2.5vw;
        }
        h4{
            font-size: 2vw;
            margin: 0;
            position: relative;
            
        }
    }



.box {
    height: 49vh;
    width: 20vw;
    margin: 5px;
    left: -10px;
    position: relative;
    float: left;
    cursor: pointer;
    z-index: 1;
    // opacity: .8;
    // border-radius: 10px;
    background: rgba(255, 255, 255, 0.582);
    transition: background-color 0.2s linear;
    
}
.box:hover {
    opacity: 1;
    background-color: #222;
    
    .day {color:white;}
    

   
}

.fading{
  -webkit-animation-name: fading;
  -webkit-animation-duration: 1.8s;
  animation-name: fading;
  animation-duration: 1.8s;
}

@-webkit-keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}

@keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}


/////modal

.modal2 {
  position: absolute;
  height: 100vh;
  top: 5px;
  left: 60px;
  z-index: 9;
  background: rgba(34, 34, 34, 0.741);
  
  .modalContainer {
     width: 85vw;
      margin: auto;
    
  }

  .modalHeading {
      padding: 1px;
      background: $gradient-dark;
      color: white;
    //   border-radius: 5px;

  }

 

  .modalContent {
      height: 98vh;
    //   padding: 44px;
      margin: 5px;
      opacity: 1;
      background: rgba(0, 0, 0, 0.253);
      background-size: cover;
      background-position-x: 50%; 

       .mcback {
      position: relative;
      height: 98vh;
       width: 100%;
        background-size: cover;
        left: 0;
        top: 0;
        opacity: .5;
        z-index: 1;
      background-position-x: 50%; 
  }

    .mctext {
        position: absolute;
        top:45%;
        z-index: 9;
        padding: 55px;
            h2 {
                font-size: 3vw;
                
            }
            h3 {
                font-size: 6vw;
            }
            p {
                font-size: 2vw;
            }
    }
      
  }

  .modalContent:after {
      content: '';
      opacity: .5;
  }
  .close {
      
      position: relative;
      padding: 10px 16px 0 0;
      color: white;
      font-size: 38px;
      z-index: 99;
      float: right;
      cursor: pointer;
    
      
  }
  .close:hover {
      transform: scale(1.4);
      transition: all .5s;
  }
}

@media screen and (max-width: 1024px) {
        #topic {
            height: 400px;

        }
        .wrapper {
            height: 400px;
            position: relative;
            
        }
        h1 {
            top: 5vh;
            }
        .parallax-mobile {
            background-image: url('../../assets/img/intro/visitback.jpg');
            background-repeat: no-repeat;
            position: absolute;
            z-index: 0;
            top: 0;
            left: 0;
            opacity: .2;
            background-size: 100% auto;
            height: 100%;
            width: 100%;
            }
            .card {
                height: 150px;
                cursor: pointer;
                margin-left: 10px!important;
                top: 5vw;
                background: rgb(77, 74, 74);
                position: relative;
            }

               .day {
                text-align: center;
                position: relative;
                top:35px;
                color: white;
                transition: all 1s;                
                h2 {
                    font-size: 2.5vw;
                }
                h4{
                    font-size: 2vw;
                    margin: 0;
                    position: relative;
                    
                }
            }


    .modal2 {
  position: fixed;
  height: auto;
  top: 100px;
  left: 60px;


  .modalContent {
      height: 75vh;

       .mcback {
      height: 75vh;
  }

    .mctext {

            h2 {
                font-size: 30px;
                
            }
            h3 {
                font-size: 45px;
                font-weight: 500;
            }
            p {
                font-size: 20px;
            }
    }
      
  }

}



 }


     @media screen and (max-width: 748px) {
           .wrapper {
            height: 350px;
            position: relative;
            
        }
         .row {
             left: 3%;
             position: relative;
         }
            .card {
                height: 100px;
                cursor: pointer;
                margin-left: 10px!important;
                // top: 5vw;
                background: $gradient-dark;
                background-position: 0px 0px;
                background-size: 200%;
                position: relative;
                color:white;    
            }

            
    .modal2 {
  position: fixed;
  height: auto;
  top: 60px;
  left: 30px;


  .modalContent {
      height: 75vh;

       .mcback {
      height: 75vh;
  }

    .mctext {

            h2 {
                font-size: 18px;
               
            }
            h3 {
                font-size: 25px;
                font-weight: 500;
           }
            p {
                font-size: 15px;
           }
    }
      
  }}

            
     }


</style>



