import Vue from 'vue'
import Router from 'vue-router'
import App from '@/App'
import Home from '@/pages/Home.vue'
import Study from '@/pages/Study.vue'
import series from '@/components/study-components/series.vue'
import test from '@/components/study-components/seriestest.vue'
import videos from '@/components/study-components/video.vue'
import Events from '@/pages/Events.vue'
import Gallery from "@/pages/Gallery.vue"
import Map from "@/pages/Map.vue"
import Contact from "@/pages/Contact.vue"
import Member from "@/pages/Member.vue"
import Donate from "@/pages/Donate.vue"
import Dashboard from "@/pages/Dashboard.vue"
import dashHome from '@/components/dash-components/dash-home.vue'
import dashWel from '@/components/dash-components/dash-wel.vue'
import dashCal from '@/components/dash-components/dash-cal.vue'
import dashTopic from '@/components/dash-components/dash-topic.vue'
import dashPreach from '@/components/dash-components/dash-preach.vue'
import dashMission from '@/components/dash-components/dash-mission.vue'
import dashAudio from '@/components/dash-components/dash-audio.vue'
import dashVideo from '@/components/dash-components/dash-video.vue'



Vue.use(Router)

const router = new Router({
  routes: [
    { path: '/', component: Home},
    { path:"/crecimiento", component: Study},
    { path:"/crecimiento/estudios", component: series},
    { path:"/test", component: test},
    { path:"/crecimiento/videos", component: videos},
    { path:"/calendario", component: Events},
    { path:"/fotos", component: Gallery},
    { path:"/direcciones", component: Map},
    { path:"/contacto", component: Contact},
    { path:"/donar", component: Donate},
    { path:"/miembros", component: Member, props: true},
    { name: "dashboard", path:"/dashboard/:email",  redirect: '/dashboard/:email/home', component: Dashboard, props: true, meta:{requiresAuth: true}, children: [
    { name: "home", path:"/dashboard/:email/home", component: dashHome,},
    { name: "welcome", path: "/dashboard/:email/home/welcome",  component: dashWel},
    { name: "topics", path: "/dashboard/:email/home/topics", component: dashTopic},
    { name: "preacher", path: "/dashboard/:email/home/preacher", component: dashPreach},
    { name: "mission", path: "/dashboard/:email/home/mission", props: true, component: dashMission},
    { name: 'calendar', path: "/dashboard/:email/home/calendar", component: dashCal},
    { name: 'audio', path: "/dashboard/:email/home/audio", component: dashAudio},
    { name: 'video', path: "/dashboard/:email/home/video", component: dashVideo},
      
    ]},
  ],
  mode: "history"
})

export default router;





