<template>
  <div>

       <div class="row">
            <div class="col s12 m6"  v-for="(item, key, index) in days[0]" :key= index>
                <div class="card grey darken-3">
                    <div class="card-image">
                    <img :src="item.url" style="max-height: 250px;">
                    <!-- <span class="card-title">Card Title</span> -->
                    </div>
                    <div class="card-content white-text">
                    <span class="card-title">{{item.day}}</span>
                    <button class="btn-floating btn-large" @click="modalEdit = true; passData(item)"><i class="fa fa-pencil" aria-hidden="true"></i></button>

                    <!-- <p>I am a very simple card. I am good at containing small bits of information.
                    I am convenient because I require little markup to use effectively.</p> -->
                    </div>
                </div>
            </div>
        </div>

          <transition name="slideUp" >
                    <div class="modalEvent" id="addModal" v-if="modalEdit" >
                        <div class="modalContainer">
                            <div class="modalHeading">
                                <div class="close" @click="modalEdit = false; topicsUrl= null; topic_name = null; topic_des= null">
                                    &times;
                                </div>
                                <div class="modalContent row">
                                    <div class="col s3"><h3>{{item.day}}</h3></div>
                                    <div class="col offset-s2 s1">
                                       <button v-if="!topicsUrl"  class="series-upload btn-floating btn-large" @click="pickImage()"><i class="fa fa-picture-o" aria-hidden="true"></i></button>
                                    <button v-else class="confirm-upload btn-floating btn-large" @click="uploadImage(); modalEdit = false; imgUp = true;"><i class="fa fa-check" aria-hidden="true"></i></button>

                                        <input type="file" id="imageInput" style="display:none" accept="image/*" ref="imageInput" @change="AddImage">
                                    </div>
                                     <div class="input-field col s12">
                                          <input type="text" v-model="topic_name">
                                          <label>Topic Name</label>
                                        </div>
                                        <div class="input-field col s12">
                                          <input type="text" v-model="topic_des">
                                          <label>Topic Description</label>
                                        </div>
                                      <div class="col s12">
                                        <p style="margin-top: 30px;">File Preview:</p>
                                        <img :src="topicsUrl" alt="" style="width: 100%;"> 
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                        <v-snackbar :timeout="6000" top right multi-line v-model="imgUp">Photo Updated!&nbsp;<strong>REFRESH PAGE FOR CHANGES!!</strong>
                        <v-btn flat color="cyan" @click.native="imgUp = false">Close</v-btn></v-snackbar>

            </transition>


  </div>

</template>

<script>

import firebase from 'firebase';
import axios from 'axios';
import {realDB} from  '../../firebase/firebase';
import {s3} from  '../../aws/aws-topics';


export default {
  name: 'dash-topic',
  data(){
      return {
          days: [],
          text: null,
        //   imageUrl: "",
          modalEdit: false,
        //   image: null,
        //   imageFile: null,
        //   imageFileName: ''
          imagefiles: '',
          imageName: '',
          imgUp: false,
          topicsUrl: null,
          item: null,
          topic_name: null,
          topic_des: null
      }
  },
    methods: {
            getDays(){
          var arr = []
                realDB.ref('topics').on(('value'), function(snapshot){
                 arr.push(snapshot.val())
            })

            this.days = arr;
      },
        pickFile(){
            this.$refs.fileInput.click()
        },
        pickImage(){
                $('#imageInput').click()
            },
        passData(item){
            this.item = item;

            console.log(item)

        },
        AddImage(event){

            this.Imagefiles = event.target.files[0]
         
            this.imageName = this.Imagefiles.name;

            const fileReader = new FileReader()
            fileReader.addEventListener("load", () => {
                this.topicsUrl = fileReader.result;
            })
            fileReader.readAsDataURL(this.Imagefiles)



    },
        onFilePicked(event) {

            this.imageFile = event.target.files[0]
            var file = document.getElementById('uploadedFile');
            var blob = file.files[0].slice(0, -1, 'image/png'); 
            var justName = this.imageFile.name.substr(0, this.imageFile.name.lastIndexOf('.'));
            var justExt = this.imageFile.name.substr(this.imageFile.name.indexOf('.')).toUpperCase()
            var newFileName = justName+justExt;
            var newFile = new File([blob], newFileName, {type: 'image/png'});


            this.imageFile = newFile;
          
            
            const files = event.target.files

            let filename = files[0].name;
            if(filename.lastIndexOf('.') <= 0){
                return alert('add a valid file!');
            }

            const fileReader = new FileReader()
            fileReader.addEventListener("load", () => {
                this.imageUrl = fileReader.result;
            })
            fileReader.readAsDataURL(files[0])
            this.image = files[0].name
            this.imageFileName = this.image.substr(0, this.image.lastIndexOf('.'));
   
           
        },
      uploadImage () {

            this.item.day = this.item.day.replace(/ /g, "-")
            this.imageName = this.imageName.replace(/ /g, "-")

             var albumKey = 'topics/' + encodeURIComponent(this.item.day) + '/';
                s3.listObjects({Prefix: albumKey}, function(err, data) {
                
                    var objects = data.Contents.map(function(object) {
                    return {Key: object.Key};
                    });

                    s3.deleteObjects({
                    Delete: {Objects: objects, Quiet: true}
                    }, function(err, data) {
                  
                    });
                });

                    s3.putObject({Key: albumKey}, function(err, data) {
             
                    });


            var albumPhotosKey = 'topics/' + encodeURIComponent(this.item.day) + '/';
           
           let extn = this.Imagefiles.name.split('.').pop();

           var contentType;

            if (extn == 'png' || extn == 'PNG' || extn == 'JPG' || extn == 'jpg' || extn == 'jpeg' || extn == 'JPEG') contentType = "image/" + extn;

            var photoKey = albumPhotosKey + this.imageName;


            s3.upload({
                Key: photoKey,
                Body: this.Imagefiles,
                ContentType: contentType,
                ACL: 'public-read'
            }, function(err, data) {

            });


            realDB.ref("topics").child(this.item.day).set({
                day: this.item.day,
                url: "https://s3.us-east-2.amazonaws.com/idctopics/topics/"+ this.item.day + "/" + this.imageName,
                topic_name: this.topic_name,
                topic_des: this.topic_des
            })

            this.getDays()

      }
    },
    created(){
          var arr = []
                realDB.ref('topics').on(('value'), function(snapshot){
                 arr.push(snapshot.val())
            })

            this.days = arr;
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main';
@import '../../assets/materialize.min.css';

.card-content {
    position: relative;
}
.btn-floating {
    position: absolute;
    right: 15px;
    top: 15px;
    background: $gradient-dark;
}

.series-upload, .confirm-upload {
    position: relative;
    margin-right: 10px;
}
h3, h4{
    color:white;
}

.modalEvent{
  position: fixed;
  // padding-top: 5vw;
  padding-left: 8vw;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  z-index: 99;
  background: rgba(34, 34, 34, 0.741);
  overflow-y: scroll;
  
  .modalContainer {
     width: 80vw;
      margin: auto;
      margin-top: 2vh;
  }

  .modalHeading {
      padding: 6px;
      background: #222;
      color: white;
  }

  .modalContent {
      min-height: 90vh;
      padding: 44px;
      margin: 10px;
      background: rgba(0, 0, 0, 0.253);
      background-size: cover; 

      .collection-item:hover {
        background: #222;
        left: 0px;
      }
      
  }
  .close {
      padding: 10px 16px 0 0;
      color: white;
      font-size: 38px;
      z-index: 99;
      float: right;
      cursor: pointer;
    
      
  }
  .close:hover {
      transform: scale(1.4);
      transition: all .5s;
  }
}


</style>



