<template>
  <div>
       <loader v-if="loading" />
       <div style="left: 5px; top: 15px; position:relative;" v-else>
           <div class="row">
               <div class="col s12 m12 l6" style="position:relative; margin-bottom: 15px;" v-for="(video, index) in videoId" :key="index">
               <!-- <div class="col s12 m6" style="position:relative"> -->
                        <div class="video-cover z-depth-5" :class="{ slide: video.active }">
                            <h2 class="white--text center-align">{{video.name}}</h2>
                            <p class="white--text center-align">{{video.des}}</p>
                            <a v-show="video.url" class="btn-floating btn-large waves-effect waves-light z-depth-3" target="blank" :href="video.url"><i class="material-icons pdf">picture_as_pdf</i></a>
                            
                            <i class="material-icons arrow" v-if="video.active === false" @click="toggleVideo(video);">keyboard_arrow_left</i><i class="material-icons arrow" @click="toggleVideo(video);"  v-else>keyboard_arrow_right</i>
                        </div>
                            <iframe class="video z-depth-3" height="405" :src="url + video.playlist" frameborder="0" allowfullscreen></iframe>
                   </div>
                
               </div>
            
           </div>



    
        
       
  </div>
</template>

<script>
import Loader from '../main/Loader.vue';
import {realDB} from  '../../firebase/firebase';

export default {
     name: 'videos',
    components: {
      "loader": Loader
    },
    data(){
        return {
            
            loading: true,
            url: 'https://www.youtube.com/embed/?listType=playlist&list=',
            videoId: ''
        }
    },
    methods:{
        toggleVideo(video){
            video.active = !video.active
        }
    },
    created(){
         setTimeout(() => {
                            this.loading = false;
                        }, 2000);



          var arr = [];

            realDB.ref('videos').on(('value'), function(snapshot){
                snapshot.forEach(function(child){
                    arr.push(child.val())
                })
               
            })
            this.videoId = arr;
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/materialize.min.css';
@import '../../assets/main.scss';

.slide {
    width: 5%!important;
}

.video-cover {
    background: linear-gradient(135deg, rgba(34, 34, 34, 0.856) 0%, #222 100%);
    position: absolute;
    width: 98%;
    height: 99%;
    transition: width .5s ease-in-out;
    

   
    h2, p {
        position: relative;
        top: 25%;
        transition: all .5s;
    }

    .btn-large {
        position: absolute;
        left: 50%;
        top: 70%;
    }

    .arrow {
        font-size: 8em;
        float: right;
        position: absolute;
        top: 35%;
        right: 0;
        color:white;
        cursor: pointer;
        transition: all .5s;
    }

  
}

.pdf {
    background: $gradient-dark;
    font-size: 2em!important;
 }

  .slide h2, .slide p {
      opacity: 0;
  }

  .slide i {
      
        right: -10px!important;
        top: 40%!important;
        font-size: 4em!important;
    }

    .slide .pdf {
                font-size: 2em!important;
    }

    .slide .btn-large {
        position: absolute;
        left: 30%;
        top: 80%;
    }

.video {
    width: 95%;
    margin-left: 5%;
}

@media screen and (max-width: 1024px) {
    
.video-cover {
       .btn-large {
        left: 47%;
    }}

     .video-cover{
        h2 {
            font-size: 1.7em;
            width: 60%;
            left: 20%;
            position: relative;
            text-align: center;
        }
        p {
            font-size: 1em;
        }
    }
}

@media screen and (max-width: 748px) {
    .video-cover{
        h2 {
            font-size: 2em;
        }
        p {
            font-size: 1em;
        }
    }
    .btn-large {
        position: absolute;
        left: 45%!important;
        top: 70%;
    }

      .arrow {
        font-size: 4em !important;
        float: right;
        position: absolute;
        top: 70%!important;
        right: 0;
        color:white;
        cursor: pointer;
        transition: all .5s;
    }

   
}


</style>



