<template>
  <div>
       <div class="row">
 

        <div class="input-field col s12">
            <h2 class="white-text">{{mission[0].title}}</h2>
            <input placeholder="Placeholder" v-model="mission[0].title" type="text">
             <!-- <label for="first_name">First Name</label> -->
            <h4 class="white-text">${{mission[0].count}}</h4>
            <input placeholder="Placeholder" v-model="mission[0].count" type="text">

            <h6 class="truncate white-text">{{mission[0].text}}</h6>
            <textarea id="textarea1" cols="120" rows="15" spellcheck="false" v-model="mission[0].text" class="materialize-textarea"></textarea>
            <button class="btn-large btn-floating right hoverable" @click="onCancel();"> <i class="material-icons">clear</i> </button>
            <button class="btn-large btn-floating right hoverable" @click="onUpdate();"> <i class="material-icons">check</i> </button>
            <p></p>
        </div>


    </div>   

    <v-snackbar :timeout="3000" top center multi-line v-model="up">Data Updated!</v-snackbar>
  </div>
</template>

<script>
import db from  '../../firebase/firebase';


export default {
  name: 'dash-mission',
  props: ['email'],
  data(){
      return {
            mission: [],
            up: false
      }
  },
  methods: {
       getData(){
          db.collection('MissionData').get().then(querySnapshot => {querySnapshot.forEach(doc => {
          this.mission.push(doc.data())
      })
    })

    },
    onCancel(){
        this.$router.go({path: '/dashboard/'+ this.$route.params.email +'/home/mission'});


    },
    onUpdate() {
        db.collection("MissionData").doc("9cJRj1M7zqTynqgaHKAE").set({
                count: this.mission[0].count,
                text: this.mission[0].text,
                title: this.mission[0].title
            })
            .then(() => {
               
            })
            .catch(function(error) {
                 alert("text updated failed! Try again!")
            });    
         this.up = true;
        // this.$router.go({path: '/dashboard' });
        
      }
    },
  
    mounted(){
        this.getData();
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../../assets/main';
@import '../../assets/materialize.min.css';

h1 {
    color:white;
}

p {
    color:  lightcyan;
}



.input-field {
    input, textarea {
        color: cyan;
    }
}

.btn-floating {
    background: $gradient-dark;
    margin-right: 15px;
}

      @media screen and (max-width: 748px) {
          h2 {
              font-size: 25px;
          }
      }

</style>



