<template>
  <div class="contain">
      <div class="back"></div>
    <loader v-if="loading"/>
     <div v-show="loading === false" class="row event-row">
         <div class="chips">
           <div class="chip black">Servicio</div>
            <div class="chip red">Cantos</div>
            <div class="chip blue">Estudio</div>
         </div>
        <div class="col s12 m12 l6 z-depth-4 main-container">
               <div class="events-cont" > 
                    <div class="row" >
                        <div class="mySlides fading col s12"  v-for="(months, index) in events.months" :key="index" v-if="months.month !== null" v-show="months.id == currentMonth">
                                <h3>{{months.month}}</h3>
                                <div class="divider"></div>
                                <div class="card-cont">
                                       <div class="card" v-for="(event, index) in months.event" :key="index" :style="{'background-color':event.color}">
                                        <!-- <div class="card-image waves-effect waves-block waves-light">
                                        <img class="activator" src="images/office.jpg">
                                        </div> -->
                                        <div class="card-content">
                                        <span class="card-title activator white-text">{{event.name}}<i class="material-icons right" >more_vert</i></span>
                                               <p class="white-text"><strong>Fecha:</strong> {{event.date}} | <strong>Hora:</strong> {{event.time}}</p>
                                        </div>
                                        <div class="card-reveal" >
                                        <span class="card-title" style="font-size: 16px; text-decoration: underline;"><i class="material-icons right">close</i></span>
                                         <p style="font-weight: 500">{{event.details}}</p>
                                        </div>
                                    </div>
                                </div>
                               
                           
                                </div>
                             
                            </div>  
                        </div>
        </div>
        <div class="col s12 m12 l6 calendar"> 
            <v-calendar class="z-depth-4" :attributes='attrs' is-single-paned  is-expanded > </v-calendar>
        </div>

     
     </div>
</div> 
</template>

<script>
import db from  '../firebase/firebase';
import realDB from  '../firebase/firebase';
import Loader  from '../components/main/Loader.vue';

export default {
  name: 'Events',
  components: {
      "loader": Loader
  },
  data() {
    return { 
        arrowLeft: '',
        arrowRight: '',
         attrs: [
            {
            key: 'Cantos',
                dates: { weekdays: [2] },
                highlight: {
                    backgroundColor: '#ff8080',
                    
                },
                // Just use a normal style
                contentStyle: {
                    color: '#fafafa',
                },
                contentHoverStyle: {
                    color: '#222'
                },
                // Our new popover here
                popover: {
                    label: 'Cantos! 7-8PM',
                }
            },
            {
            key: 'Estudio',
                dates: {weekdays: [4]},
                highlight: {
                    backgroundColor: '#6ccbeb'
                },
                // Just use a normal style
                contentStyle: {
                    color: '#fafafa',
                },
                contentHoverStyle: {
                    color: '#222'
                },
                // Our new popover here
                popover: {
                    label: 'Estudio! 7-8PM',
                }
            },
            {
            key: 'Servicio',
                dates: {weekdays: [1]},
                highlight: {
                    backgroundColor: '#222'
                },
                // Just use a normal style
                contentStyle: {
                    color: '#fafafa',
                },
                contentHoverStyle: {
                    color: '#fff'
                },
                // Our new popover here
                popover: {
                    label: 'Servicio 9:30AM-11:30AM & 3-4PM',
                }
            },
            // {
            //     key: 'salida',
            //     dates: [
            //         { start: new Date(2018, 3, 12), 
            //             span: 2 } // Span is number of days
            //   ],
            //     highlight: {
            //         backgroundColor: 'yellow',
            // } 
            // }
      ],
      events: {
          months:[]
      },
      eventsArray: [],
      currentMonth: "",
      eventClicked: {},
      showingModal: false,
      loading: false
    }
  },
   methods: { 
      getEvents(){

         var d = new Date();
            var m = d.getMonth();
            var slideIndex = m + 1;

            console.log(slideIndex)

            this.currentMonth = slideIndex - 1;

            showSlides(slideIndex);   

            $(".c-arrow-layout .vc-angle-right").click(function(){
                   showSlides(slideIndex += 1);
                })

             $(".c-arrow-layout .vc-angle-left").click(function(){

                 console.log("clicked")
                   showSlides(slideIndex -= 1);
                })

            function currentSlide(n) {
            showSlides(slideIndex = n);
            }
            function showSlides(n) {
            var i;
            var slides = document.getElementsByClassName("mySlides");
            if (n > slides.length) {slideIndex}      
            if (n < 1) {slideIndex}
            for (i = 0; i < slides.length; i++) {
                $(slides[i]).hide();
                
            }

            $(slides[slideIndex-1]).show();

            }

            
      }
  },
  mounted(){
      this.getEvents();

      this.arrowLeft = document.getElementsByClassName("vc-angle-left");
      this.arrowRight = document.getElementsByClassName("vc-angle-right");


  },
  created(){
    // console.log(this.attrs)
        db.collection("CalendarData").get().then(querySnapshot => {querySnapshot.forEach(doc => {

                this.attrs.push(doc.data())

            })

        })

          db.collection("EventsData").orderBy('id').get().then(querySnapshot => {querySnapshot.forEach(doc => {

                this.events.months.push(doc.data())

                console.log(this.events.months)
                

            })

        })
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';
@import '../assets/materialize.min.css';
.chips {
    position: absolute;
    left: 75%;
    top: -50px;
    .chip {
        color:white;
    }
}
.red {
    background: #ff8080 !important;
    // left: 60px;
}
.blue {
    background: #6ccbeb !important;
    // left: 110px;
}

.divider {
    position: relative;
    height: 4px;
    width: 100%;
    left: 0px;
    opacity: .9;
    z-index: 1;
    background: $gradient-dark;
    transition: all .7s;
    opacity: .7;
}

.contain {
    width: 95vw;
    height: 100vh;
    background:$gradient-2;
    background-size: cover;
    position: relative;
    z-index: 2;
    
}
.back {
    width: 95vw;
    height: 100vh;
    background: url('../assets/img/events.jpg');
    background-size: cover;
    position: absolute;
    opacity: .2;
    z-index: 0;
    
}
.card-cont {
    position: relative;
    overflow-y: scroll;
    max-height: 360px;

    
}


.row {
    position: relative;
    left: 25px;
    top: 15%;
    width: 90%;
}


.header {
    text-align: center;
}


.slideshow-container {
    position: relative;
    // width: 100%;
    display: block;

  
}

.main-container {
    background:white;
}

div.c-day-content {
  border-radius: 0%!important;
}


  .mySlides{
      width: 100%;
      margin-top: -40px;

        h3 {
            color:#222;
            font-weight: 300;
            text-align: center;
            // margin: 5px;
        }
    }

.events-cont {
    width: 110%;
    height: 500px;
    
}

.eventMonth {
    height: 100%;
    position: absolute;
}


    /* Fading animation */
.fading{
  -webkit-animation-name: fading;
  -webkit-animation-duration: .7s;
  animation-name: fading;
  animation-duration: .7s;
  
}

@-webkit-keyframes fading {
  from {opacity: .4} 
  to {opacity: 1}
}

@keyframes fading {
  0% {opacity: .1; transform: scale(.8)} 
  50% {opacity: 0; transform: scale(.6)}
  100% {opacity: 1; transform: scale(1)}
}

    @media screen and (max-width: 1024px) {

        .chips {
    left: 0;
    width: 300px;
  
}

.back {
    width: 100vw;
    height: 110vh;
    background: url('../assets/img/events.jpg');
    background-size: cover;
    position: absolute;
    opacity: .2;
    z-index: 0;
    overflow: hidden;
    
}

        .contain {
        width: 100vw;
        height: 115vh;
        background: $gradient-dark-2;
        overflow: hidden;
    }

            .card-cont {
            position: relative;
            overflow-y: scroll;
            width: 100%;
            max-height: 360px!important;
        
}   
        .events-cont {
            width: 110%;
            height: 300px;
            
        }
        .row {
            position: relative;
            left: 0px;
            top: 6%;
            width: 100%;
        }

        .event-row {
            
            width: 95%!important;
            margin-top: 50px;
        }

        .s12 {
            height: 500px!important;
        }
        .calendar {
            width: 100%!important;
            top: 30px;
            position: relative;
        }
        .main-container {
        background:white;
        left: 10px!important;
        position: relative;
        // margin-top: -50px;
        width: 98%!important;
        height: 300px;
        }

          .mySlides{
      margin-top: -10px;
        width: 90%!important;
        height: auto;

        h3 {
            color:#222;
            // width: 90%;
            font-weight: 300;
            text-align: center;
            // margin: 5px;
        }
    }

    }
     @media screen and (max-width: 748px) {
                 .chips {
    position: absolute;
    left: 25%;
    top: -50px;
    .chip {
        color:white;
    }
}

        .contain {
        width: 100vw;
        height: 1050px;
        background: $gradient-dark-2;
        overflow: hidden;
    }


        .main-container {
        background:white;
        left: 10px!important;
        position: relative;
        // margin-top: -50px;
        width: 95%!important;
        height: 300px;
        }

          .mySlides{
      margin-top: -10px;
        width: 90%!important;
        height: auto;

        h3 {
            color:#222;
            // width: 90%;
            font-weight: 300;
            text-align: center;
            // margin: 5px;
        }
    }

     }


</style>



