<template>
        <div class="row">
                 <line-chart class="z-depth-3 chart col s12 "></line-chart>
                 <pie-chart class="z-depth-3 chart col m6 s12" :width="500" :height="200"></pie-chart>
                 <bar-chart class="z-depth-3 chart offset-m1 col m5 s12" :width="400" :height="200"></bar-chart>
         </div>
  
</template>

<script>

  import LineChart from '../../components/dash-components/dash-charts/dash-line-chart.vue'
  import PieChart from '../../components/dash-components/dash-charts/dash-pie-chart.vue'
  import BarChart from '../../components/dash-components/dash-charts/dash-bar-chart.vue'

export default {
  name: 'dash-home',
      components: {
      LineChart,
      PieChart,
      BarChart
  },

}
</script>

<style lang="scss" scoped>

@import '../../assets/main';
@import '../../assets/materialize.min.css';

.chart {
    padding: 30px !important;
    margin-bottom: 20px;
}


</style>




