<template>
  <div>
    <h4 class="header white-text">Months</h4>
      <div class="row">
    <div class="col s12 m4" v-for="(month, index) in events.months" :key="index" @click="editMonth(month); modalEv= true;">
       <div class="card">
        <div class="card-content white-text">
          <span class="card-title">{{month.month}}</span>
        </div>
      </div>
  </div>
    </div>
  
      <transition name="slideUp">
               <div class="modalEvent" id="addModal" v-if="modalEv" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="modalEv = false; deletedItem = false;">
                            &times;
                        </div>
                        <div class="modalContent">
                          <div class="event-list">
                            <ul class="collection with-header" style="border:none;">
                              <li class="collection-header" style="background: #222; border:none">
                                <h4>Event in {{monthData.month}}</h4>
                                  <div class="fixed-action-btn addbtn" @click="addItem = true;" v-if="!addItem === true">
                                    <a class="btn-floating btn-large">
                                      <i class="fa fa-plus"></i>
                                    </a>
                                  </div>
                                </li>
                                <transition name="slide-in">
                                <li class="add-item" v-if="addItem">
                                   <form @submit.prevent="addEvent" class="col s12">
                                      <div class="row">
                                        <div class="input-field col s4">
                                          <input type="text" v-model="event.name" required>
                                          <label>Name</label>
                                        </div>
                                         <div class="input-field col s2">
                                          <Datepicker class="picker" style="color:#fff;" placeholder="Start Date" v-model="event.date"/>
                                        </div>
                                          <div class="input-field col s2">
                                          <input type="text" v-model="event.days" required>
                                          <label># of Days</label>
                                        </div>
                                        <div class="input-field col s2">
                                          <input type="text" v-model="event.time"  required>
                                          <label>time</label>
                                        </div>
                                      </div>
                                      <div class="row">
                                        <div class="input-field col s9">
                                          <input type="text" v-model="event.details"  required>
                                          <label>details</label>
                                        </div>
                                        <div class="col s3">
                                          <label >Color of Event:</label>
                                          <compact-picker v-model="colors" :style="{'background-color': this.colors.hex}"/>
                                        </div>
                                      </div>
                                      <div class="confirm-btn">
                                          <div class="fixed-action-btn" @click="addEvent(); addItem = false"><a class="btn-floating"><i class="material-icons yes">check</i></a></div>                                      
                                          <div class="fixed-action-btn" @click="addItem = false"><a class="btn-floating"><i class="material-icons no">clear</i></a></div>  
                                      </div>
                                   </form>
                                </li>
                                </transition>
                              <li class="collection-item item" v-for="(event, index) in monthData.event" :key="index" :style="{'background-color': event.color}">
                                <div>
                                  <div class="event-items row" >
                                    <li class="col s2">{{event.name}}</li>
                                    <li class="col s2">{{event.date}}</li>
                                    <li class="col s2">{{event.time}}</li>
                                    <li class="col s4 toverflow">{{event.details}}</li>
                                    <li class="col s2">
                                      <a href="#!" class="secondary-content" @click="deleteEvent(event, index)"><i class="material-icons list-icons">delete</i></a>
                                    </li>
                                  </div>
                                  </div>
                                </li>
                            </ul>
                          </div>
                           <!-- <div class="alert" v-show="deletedItem">***AFTER DELETING ITEMS REFRESH PAGE TO SEE CHANGES!!***</div> -->
                        </div>
                    </div>
                </div>
            </div>
    </transition>

<div id="snackbar" class="month z-depth-3">New event added to {{monthData.month}}!</div>
<div id="snackbar" class="edit z-depth-3">Event has been removed!</div>

  </div>

</template>

<script>
import db from  '../../firebase/firebase'
import Datepicker from 'vuejs-datepicker';
import compact from '../../../node_modules/vue-color/src/components/Compact.vue'
import {realDB} from  '../../firebase/firebase';

let defaultProps = {
  hex: '#194d33',
  hsl: {
    h: 150,
    s: 0.5,
    l: 0.2,
    a: 1
  },
  hsv: {
    h: 150,
    s: 0.66,
    v: 0.30,
    a: 1
  },
  rgba: {
    r: 25,
    g: 77,
    b: 51,
    a: 1
  },
  a: 1
}


export default {
  name: 'dash-cal',
  components: {
    Datepicker,
      'compact-picker': compact,
   },
  data(){
      return {
          colors: defaultProps,
          modalEv: false,
          modal: false,
          snackbarEdit: false,
          // deletedItem: false,
          addItem: false,
          editItem: true,
          confirmItem: false,
          text: null,
          dialog: false,
          events: {
            months: []
          },
          monthData: {
            id : null,
            month: '',
            color: '',
            event:[]
          },
          event: {
            name : "",
            date: null,
            days: null,
            time: null,
            details: null
          },
          newEvents: null
      }
  },
  computed: {


     
    
  },
    methods: {
      editMonth(month){

        this.monthData = month

        this.monthData.event.sort(function(a, b){return (a.date > b.date) ? 1 : ((b.date > a.date) ? -1 : 0);})

      },
      addEvent(){

      let newDate =this.event.date.toLocaleDateString()

      console.log(newDate)

        var obj = {
              name: this.event.name,
              date: newDate,
              time: this.event.time,
              details: this.event.details,
              color: this.colors.hex
            }

        this.monthData.event.push(obj);

        db.collection('CalendarData').doc(this.monthData.month + "-" + this.event.name).set({
                  key: this.event.name,
              dates: [
                { start: this.event.date, 
                  span: parseInt(this.event.days) } // Span is number of days
              ],
            highlight: {
              backgroundColor: this.colors.hex
            },
            contentStyle: {
                      color: '#fafafa',
            },
            popover: {
                      label: this.event.name + " " + this.event.time,
                  }

              }).then(()=>{
                //  this.snackbar = true;
                //  this.monthData.event.sort(function(a, b){return (a.date > b.date) ? 1 : ((b.date > a.date) ? -1 : 0);})

              })

              this.event.name = ""
              this.event.date = null
              this.event.days = null
              this.colors.hex = null
              this.event.details = null

        db.collection('EventsData').doc(this.monthData.month).set({
                  event: this.monthData.event,
                  id: this.monthData.id,
                  month: this.monthData.month

              }).then(()=>{
                $('.month').addClass('show');
                setTimeout(function(){ $('.month').removeClass('show')}, 3000);

                 this.event.event.sort(function(a, b){return (a.date > b.date) ? 1 : ((b.date > a.date) ? -1 : 0);})

              })
    },
      deleteEvent(event, index){
         var newArr = [];

        newArr = Array.prototype.slice.call(this.monthData.event)

        // var index = newArr.indexOf(this.editEvent)

        if (index > -1) {
            newArr.splice(index, 1);
        }

        this.monthData.event = newArr;

      db.collection('EventsData').doc(this.monthData.month).set({

                  event: this.monthData.event,
                  id: this.monthData.id,
                  month: this.monthData.month

              }).then(()=>{
                 
                $('.edit').addClass('show');
                setTimeout(function(){ $('.edit').removeClass('show')}, 3000);
                 
              })

              this.deletedItem = true;
              console.log(event.name)
    
    db.collection('CalendarData').doc(this.monthData.month + "-" + event.name).delete().then(()=>{
                  console.log("Document successfully deleted!");
                }).catch(function(error) {
                    console.error("Error removing document: ", error);
                });



            }
      
 
   },
    created(){
           db.collection("EventsData").orderBy("id").get().then(querySnapshot => {querySnapshot.forEach(doc => {

                this.events.months.push(doc.data())

                })

            })

    }
    
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
// @import '../../assets/vuetify.min.css';
@import '../../assets/main';
@import '../../assets/materialize.min.css';



.alert {
  position: relative;
  color: white;
  font-weight: 700;
  text-align: center;
}

.months {
  // background:$gradient-2;
  // padding: 20px 20px;
}
h1 {
    color:white;
    font-size: 12px;
}

.header {
  border-bottom: white 2px solid;
}

.card {
  cursor: pointer;
  transition: all .3s ease-in-out;
  background: $gradient-dark-2;
  background-size: 150%;
  background-position-x: 40%;
}
.card:hover {
   transform: scale(1.05)
}

.event-items {
  position: relative;
  z-index: 999;

  li {
    font-size: 1.1vmax;
  }
}

.toverflow {
  text-overflow: ellipsis;
  white-space: nowrap;
  overflow: hidden;
}
.material-icons {
  line-height: 0px;
  color:white;
}
.fa-plus {
  left: 1px;
  position: relative;
}
.list-icons {
  padding-left: 10px;
  top: 5px;
  position: relative;
}
.list-icons:hover {
  color:#6ccbeb;
}

.add-item {
  height: 275px;
}
.confirm-btn{
  position: relative;
  margin-top:0px;
  float: right;
  .fixed-action-btn {
      display: inline-block;
      position: relative;
      margin-right: 10px;

      .btn-floating {
       background: rgb(61, 61, 61);
       opacity: .8;
       transition: all .3s ease-in-out;
      }
      .btn-floating:hover {
        opacity: 1;
      }

      .yes:hover {
        color: rgb(30, 209, 30);
        transition: color .3s ease-in-out;
      }
      .no:hover {
        color: red;
        transition: color .3s ease-in-out;
      }
    }
}
.addbtn {
  position: fixed;
  top: 80px;
  right: 170px;
  .btn-large {
    background: $gradient-2;
    opacity: .8;
    transition: all .3s ease-in-out;
  }
  .btn-large:hover {
    opacity: 1;
  }
}

.slide-in-enter-active {
  transition: all .3s ease-in-out;
  transition-delay: .2s;
}
.slide-in-leave-active {
  transition: all .3s ease-in-out;
}
.slide-in-enter, .slide-in-leave-to
/* .slide-fade-leave-active below version 2.1.8 */ {
  transform: translateY(-150px);
  opacity: 0;
}
  /* label color */
   .input-field label {
     color: white;
   }
   /* label focus color */
   .input-field input[type=text]:focus + label {
     color: #6ccbeb!important;
   }



/////modal

.modalEvent{
  position: fixed;
  // padding-top: 5vw;
  padding-left: 8vw;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  z-index: 9;
  background: rgba(34, 34, 34, 0.741);
  overflow-y: scroll;
  
  .modalContainer {
     width: 80vw;
      margin: auto;
      margin-top: 2vh;
  }

  .modalHeading {
      padding: 6px;
      background: #222;
      color: white;
  }

  .modalContent {
      min-height: 90vh;
      padding: 44px;
      margin: 10px;
      background: rgba(0, 0, 0, 0.253);
      background-size: cover; 
  }

  .item {
    height: 50px;
    transition: all .2s ease-in-out;
  }
  .item:hover {
    background: rgb(56, 56, 56)!important;
  }
  .close {
      padding: 10px 16px 0 0;
      color: white;
      font-size: 38px;
      z-index: 99;
      float: right;
      cursor: pointer;
    
      
  }
  .close:hover {
      transform: scale(1.4);
      transition: all .5s;
  }
}

</style>



