<template>
  <div id="preacher" >
      <div class="preacher-intro">
          <img class="hide-on-small-only" src="../../assets/img/ricardo3.png" alt="">
            <button class="z-depth-3 center" @click="showingModal = true;">INFORMACION</button>
      </div>  

      
       <transition name="slide-fade">
               <div class="modall" id="addModal" v-if="showingModal" >
                <div class="modalContainer">
                    <div class="modalHeading">
                        <div class="close" @click="showingModal = false;">
                            &times;
                        </div>
                        <div class="modalContent">
                            <div class="row">
                                <div class="text col s12">
                                    <h1 style="font-size: 2vmax;">PREDICADOR | RICARDO BARRERA</h1>
                                    <p v-html="preacherText[0].text">
                                </p>
                                </div>
                            </div>
                          
                            
                        </div>
                    </div>
                </div>
            </div>
            </transition> 
  </div>
</template>

<script>

import db from  '../../firebase/firebase'

export default {
  name: 'preacher',
  data(){
      return {
          showingModal: false,
          preacherText: []
      }
  },
   created(){

    db.collection('PreacherData').get().then 
    (querySnapshot => {
      querySnapshot.forEach(doc => {
        const data = {
          'id': doc.id,
          'text': doc.data().part1 + doc.data().part2
        }
        this.preacherText.push(data)
      })
    })
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';
@import '../../assets/materialize.min.css';


    #preacher {
        height:100vh;
        position: relative;
        z-index: 9;
        background: #fff;

        .preacher-intro {
            position: relative;
        }
     

        img {
            height: 100vh;
            width: 100%;
            opacity: .8;
        }

        button {
    position: absolute;
    margin-top: -15%;
    left: 35%;
    color:white;
    background: #222;
    padding: 20px;
    font-size: 1.5em;
    border-radius: 5px;
}
    }

    .modall {
    padding-top: 0vh;
}
.modalContent {
    height: 85vh;

    .text p { 
        font-size: 1.05vw;
        text-indent: 30px;
    }
}

    @media screen and (max-width: 1024px) {
          #preacher {
            height: 40vh;


        .preacher-intro {
            position: relative;
        }
     

        img {
    height: 40vh;
            
        }

        button {
    position: absolute;
    margin-top: -15%;
    left: 35%;
    color:white;
    background: #222;
    padding: 20px;
    font-size: 1.5em;
    border-radius: 5px;
}
    }

    .modall {
    padding-top: 0vh;
}
.modalContent {
    height: 85vh;

    .text p { 
        font-size: 1.05vw;
        text-indent: 30px;
    }
}

    }


    @media screen and (max-width: 748px) {

          #preacher {
        height:100vh;
        position: relative;
           background-image: url("../../assets/img/ricardo3-mobile.png");
           background-size: cover;
           background-position: -30px 0;
           background-repeat: no-repeat;


                button {
            position: absolute;
            margin-top: 0%;
            left: 50%!important;
            top: 85vh;
            color:white;
            background: #222;
            padding: 20px;
            font-size: 1.5em;
            border-radius: 5px;
        }
    }

    .modall {
    padding-top: 0vh;
    }
    .modalContent {
    height: 85vh;

    h1 {
        font-size: 3.5vw;
    }

    .text p { 
        font-size: 2.15vw;
    }
}

    }

</style>



