var BucketName = 'idcvideo';
var bucketRegion = 'us-east-2';
var IdentityPoolId = 'us-east-2:3b8028b4-c363-49a4-ab8e-5d284e052071';

AWS.config.update({
region: bucketRegion,
credentials: new AWS.CognitoIdentityCredentials({
    IdentityPoolId: IdentityPoolId
})
});

export const s3 = new AWS.S3({ params: {Bucket: BucketName},});




