<template>
  <div>
       <div class="row">
        <div v-if="editText.boolean === true">
         <h3 class="white-text" style="display: inline-block; margin: 30px; padding-top: 10px;">Edit text below</h3>
             <button type="submit" style="margin-right: 20px;" class="btn-floating btn-large" @click="onUpdate()"> <i class="material-icons">check</i></button>
             <button type="submit" class="btn-floating btn-large" @click="onCancel()"><i class="material-icons">clear</i></button>
          <textarea class="white-text" maxlength="1110" v-model="editText1" cols="120" rows="15" spellcheck="false"></textarea>
          <textarea class="white-text" maxlength="1110" v-model="editText2" cols="150" rows="15" spellcheck="false"></textarea>


      </div>
        
        <div class="input-field col s12" v-else>
            <h3 class="white-text" style="display: inline-block; margin: 30px; padding-top: 10px;">Preacher Info</h3>
            <button class="btn-floating btn-large" @click="onEdit(preacher[0].part1, preacher[0].part2);"><i class="material-icons">edit</i> </button>
            <div class="card z-depth-3">
            <p>{{preacher[0].part1}}</p><p>{{preacher[0].part2}}</p>
            </div>
        </div>


    </div>      
  </div>
</template>

<script>
import db from  '../../firebase/firebase';


export default {
  name: 'dash-preach',
  data(){
      return {
            preacher: [],
            editText: { text1: '', 
                      text2: '', 
                      boolean: false},
            editText1: '',
            editText2: ''
            }
  },
  methods: {
       getData(){
          db.collection('PreacherData').get().then (querySnapshot => {querySnapshot.forEach(doc => {
          this.preacher.push(doc.data())

      })
    })

    },
    onEdit(text1, text2){

        this.editText1 = text1
        this.editText2 = text2
        this.editText.boolean = true;

    },
    onCancel(){
         this.editText.boolean = false;

    },
    onUpdate() {
        db.collection("PreacherData").doc("ZkOiXP4mQCOiyZtr0W2t").set({
                part1 : this.editText1,
                part2 : this.editText2
            })
            .then(() => {
                alert("text updated!");
            })
            .catch(function(error) {
                 alert("text updated failed! Try again!")
            });    
        
        this.$router.go({path: '/dashboard' });
        
      }
    },
  
    mounted(){
        this.getData();
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../../assets/main';
@import '../../assets/materialize.min.css';

h1 {
    color:white;
}

p {
    color:  lightcyan;
}
textarea {
    margin: 20px;
    height: 150px;
    width: 95%;
    background:$gradient-dark-2;
    padding: 5px;

}
.card {
    background:$gradient-dark;
    padding: 10px;

}

.btn-floating {
    background: $gradient-dark;
    transition: all .2s ease;
    
}
.btn-floating:hover {
    transform: scale(1.05);
    transition: all .2s ease;
}
  @media screen and (max-width: 748px) {
          h3 {
              font-size: 30px;
          }
      }

</style>



