<template>
  <div>
      <div class="row" v-for="(data, index) in sections" :key="index">

        <div v-if="editSec === data.section" class="row">
         <h4 class="white-text col">{{data.section}}</h4>
            <div class="row col" style="margin-left: 50px;">
                    <button type="submit" class="btn-floating confirm hoverable" @click="onUpdate()"> <i class="material-icons">check</i></button>
                    <button type="submit" class="btn-floating confirm hoverable" @click="onCancel()"> <i class="material-icons">clear</i></button><br>
            </div>
          <textarea v-model="editText" cols="80" rows="7"></textarea>
        

      </div>

        <div class="card z-depth-1 col s12 hoverable" v-else>
            <div class="row">
            <h4 class="col">{{data.section}}</h4>    
            <button class="btn-floating col hoverable right" style="background: #222;" @click="onEdit(data);"><i class="material-icons">edit</i> </button>

            </div>     
            <p>{{data.text}}</p>
        </div>
    </div>      
  </div>

</template>

<script>
import db from  '../../firebase/firebase'


export default {
  name: 'dash-wel',
  data(){
      return {
          sections: [],
          editSec: "",
          editText: "",
          editTab: ""
      }
  },
    methods: {
       getData(){
          db.collection('HomeData').get().then (querySnapshot => {querySnapshot.forEach(doc => {
        
        this.sections.push(doc.data())

      })
    })

    },
    onEdit(section){

        console.log(section)

        this.editSec = section.section
        this.editText = section.text
        this.editTab = section.num


    },
    onCancel(){
        this.editSec = ""

    },
    onUpdate() {
        db.collection('HomeData').where('section', '==', this.editSec).get().then((querySnapshot) => {
          querySnapshot.forEach((doc) => {
            doc.ref.set({
              section : this.editSec,   
              text : this.editText,
              num : this.editTab

            }).then(this.getData());
          })
          this.$router.go({path: '/dashboard' });
        }) 
      }
    },
  
    mounted(){
        this.getData();
    }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/materialize.min.css';
@import '../../assets/main';

.card {
    background:$gradient-dark;
    padding: 10px;

    p {
        color:white;
    }

}


.btn-floating {
    margin-top: 20px;
    right:20px;
    position: relative;
    background: $gradient-dark;
    transition: all .3s;

    i{
        position: relative;
        right: 10px;
    }
}

.confirm {
    margin-left: 10px;
       
    i {
        right:0px;
    }

}

h4 {
    color:white;
}

textarea {
    margin: 20px;
    height: 100px;
    width: 95%;
    background:$gradient-dark-2;
    padding: 5px;
    color:white;

}


</style>



