<template>
  <div>
      <div class="sections">
         <div class="section-left">
              <router-link to="/crecimiento/videos">
            <div class="section boxshadow">
                 <!-- <i class="fa fa-music"></i> -->
                 <i class="material-icons ">ondemand_video</i>
            </div>
              </router-link>
      </div>
      <div class="divider"></div>
      <div class=" section-right">
           <router-link to="/crecimiento/estudios">
          <div class="section boxshadow">
                  <i class="fa fa-microphone"></i>
          </div>
           </router-link>
      </div>  
      </div>
     
      
  </div>
</template>

<script>
export default {
  name: 'Study'
  
}
</script>


<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>

@import '../assets/main';

.divider {
    position: absolute;
    height: 100vh;
    width: 30px;
    left: 51vw;
    // opacity: .9;
    z-index: 9999;
    // border-radius: 10px;
    background: $gradient-dark;
    // transition: all .7s;
}
.sections {
    width: 98vw;
}
.section-left {
    width: 55%;
    height: 100vh;
    float: left;

       div {
        background: $gradient-dark;  
        position: relative;
        top:50vh;
        left: 50%; 
        width: 10vw;
        height: 10vw;
        border-radius: 50%;
        margin-right: -50%;
        transform: translate(-50%, -50%);  
         transition: all .5s;   
    }

    .fa-music, .material-icons {
        position: relative;
        color:white;
        font-size: 6vw;
        margin-right: -50%;
        transform: translate(-50%, -50%);  
        left: 50%;
        top: 50%;
        transition: all .5s;
        cursor: pointer;
    }
 
 
    div:hover {
        background: $gradient-dark;
        transition: all .5s;
        height: 100vh;
        width: 50vw;
        border-radius: 0%;
        .fa-music, .material-icons 
        {
            font-size: 8vw;
            transition: all .5s;
            color: #222;
        
        }
    }
}

    .section-right {
        width: 45%;
        height: 100vh;
        float: left;
        position: relative;
    
        div {
            background: $gradient-dark;  
            position: relative;
            top:50vh;
            left: 50%;
            width: 10vw;
            height: 10vw;
            border-radius: 50%;
            margin-right: -50%;
            transform: translate(-50%, -50%);  
             transition: all .5s;    
        }

        
    .fa-microphone {
        position: relative;
        color:white;
        font-size: 5vw;
        margin-right: -50%;
        transform: translate(-50%, -50%);  
        left: 50%;
         top: 50%;
         transition: all .5s;
         cursor: pointer;
     
    }
            div:hover {
        background: $gradient-dark;
        transition: all .5s;
        height: 100vh;
        width: 49vw;
        border-radius: 0%;

        .fa-microphone 
        {
            font-size: 8vw;
            transition: all .5s;
            color: #222;
            
        }
    }
    }

    @media screen and (max-width: 748px) {
        .divider {
            width: 10px;
            }

             .section-right, .section-left {
       
    
        div {
      
            width: 20vw;
            height: 20vw;
      
        }


                    .fa-microphone, .fa-music {
            
                font-size: 9vw;
            
            
            }

                 div:hover {
        background: #222;

        .fa-microphone 
        {
            font-size: 8vw;
            transition: all .5s;
            color: #222;
            
        }
    }
             }
    }

</style>



