<template>
  <div id="social-media">
      <div class="social-icons">
    <ul class="accordion">
      <li class="tabs" v-for="item in social">
        <div :class="item.class">
          <a :href="item.url" target="blank">{{item.name}}</a>
        </div>
        <div class="content">
          <h1>{{item.value}}</h1>
        </div>
      </li>
    </ul>
      </div>
  </div>
</template>

<script>

import axios from 'axios';

export default {
  name: 'social-media',
  data(){
      return {
          social: []    
      }
  },
  methods: {
        onReady: function(instance, CountUp) {
        const that = this;
        instance.update(that.endVal + 100);
      },
  },
  created(){
    if ( $(window).width() > 1024) {      
       axios.get("static/scrape.php").then(response => {
                    this.social = response.data;
                    console.log(this.social)
        });
    }
  },
  mounted(){
      
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';

@import '../../assets/bootstrap.min';

a {
  text-decoration: none!important;
}

$border: #5ab2ca;
$geneicons: #fff;
$backgroundColor: #f77462;
$list: #6dc5dd;
@font-face {
  font-family: 'Genericons';
  src: url('https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.eot');
  src: url('https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.woff') format('woff'),
     url('https://s3-us-west-2.amazonaws.com/s.cdpn.io/53819/genericons-regular-webfont.eot') format('truetype');
  font-weight: normal;
  font-style: normal;
}

[class*="genericon"] {
  display: inline-block;
  width: 16px;
  height: 16px;
  -webkit-font-smoothing: antialiased;
  font-size: 16px;
  line-height: 1;
  font-family: 'Genericons';
  text-decoration: inherit;
  font-weight: normal;
  font-style: normal;
  vertical-align: top;
}

/* IE7 */
[class*="genericon"] {
  *overflow: auto;
  *zoom: 1;
  *display: inline;
}


.accordion {
  background: #222;
  width: 100%;
  // min-width: 950px;
  display: block;
  list-style-type: none;
  overflow: hidden;
  height: 70vh;
  font-size: 0;
  padding: 0;

}

.content {
    position: absolute;
    margin-left: 100%;
    left: 50%;
    top:70%;
    color:white;
    margin-right: -50%;
    transform: translate(-50%, -50%);
    transition: all 0.4s 0.1s ease-in-out ;
}

.tabs:hover .content {
    margin-left: 0%;
}

.tabs {
  display: inline-block;
  background: #222;
  border-right: black 3px solid;
  width: 25%;
  height: 100%;
  overflow: hidden;
  position: relative;
  margin: 0;
  font-size: 16px;
  transition: all 0.4s 0.1s ease-in-out ;

  &:hover {
    width: 25%;

    .social-links {
      a {
        &:before {
          margin-left: 500px;
        }

        &:after {
          margin-left: -5px;
        }
      }
    }
  }
}

.tabs:hover .paragraph {
  margin-left: 10%;
  transition: all 1s;
}

.social-links {
  display: block;

  a {
    display: block;
    text-indent: -9999px;
    font-size: 0;
    line-height: 0;


    &:before, &:after {
  transition: all 0.4s 0.1s ease-in-out ;
      width: 110px;
      height: 100%;
      position: absolute;
      text-indent: 0;
      padding-top: 55%;
      padding-left: 40%;
      display: block;
      font: normal 5.5vw Genericons;
      color: $geneicons;
    }

    &:after {
      font-size: 48px;
      width: 100%;
      padding-left: 40%;
      padding-right: 50%;
      padding-top: 50%;
      margin-left: 100%;
    font: normal 5.5vw Genericons;

    }
  }
}

.twitter-icon {
  a {
    &:before, &:after {
      content: '\f202 ';
    }

    &:after {
      background-image:linear-gradient(#7adcf9, #4bc9f5);
    }
  }
}

.facebook-icon {
  a {
    &:before, &:after {
      content: '\f204';
    }

    &:after {
      background-image:linear-gradient(#548abf, #295b9e);
    }
  }
}


.insta-icon {
  a {
    &:before, &:after {
      content: '\f215';
    }

    &:after {
background: linear-gradient( #400080, transparent), linear-gradient(200deg, #d047d1, #ff0000,#ffff00);    }
  }
}

.youtube-icon {
  a {
    &:before, &:after {
      content: '\f213';
    }

    &:after {
      background-image:linear-gradient(#df192a, #c41222);
    }
  }
}

@media screen and (max-width: 1024px) {
      #social-media {
        height: 330px;
     
    }

}

@media screen and (max-width: 1000px) {
      #social-media {
        height: 250px;
     
    }

}



@media screen and (max-width: 748px) {

    #social-media {
        height: 130px;
     
    }

} 


   



  

    

</style>



