<script>
  //Importing Line class from the vue-chartjs wrapper
  import {Line} from 'vue-chartjs'
  //Exporting this so it can be used in other components

  export default {
    extends: Line, 
    data () {
      return {
        datacollection: {
        //Data to be represented on x-axis
          labels: ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'], 
          datasets: [
            {
              label: 'Data One',
              backgroundColor: null,
              pointBackgroundColor: 'white',
              borderWidth: 1,
            //   borderColor: "white",
              pointBorderColor: '#249EBF',
              //Data to be represented on y-axis
              data: [40, 20, 30, 50, 90, 10, 20, 40, 50, 70, 90, 100]
            }
          ]
        },
        //Chart.js options that controls the appearance of the chart
        options: {
          scales: {
            yAxes: [{
              ticks: {
                beginAtZero: true
              },
              gridLines: {
                display: true
              }
            }],
            xAxes: [ {
              gridLines: {
                display: false
              }
            }]
          },
          legend: {
            display: true
          },
          responsive: true,
          maintainAspectRatio: false
        }
      }
    },
    methods:{
        colorGet(){
              var bar_ctx = document.getElementById('line-chart').getContext('2d');

           this.datacollection.datasets[0].backgroundColor = bar_ctx.createLinearGradient(0, 0, 0, 400);
            this.datacollection.datasets[0].backgroundColor.addColorStop(0, '#9c4444');
            this.datacollection.datasets[0].backgroundColor.addColorStop(1, '#4e92a8');

        }
    },
    mounted () {
        
      this.colorGet();
      this.renderChart(this.datacollection, this.options)

      
    }
  }
</script>


