<template>
  <div id="groups">
    <!-- <v-card class="show-on-small">
      <v-card-text>
        <h2 class="text-xs-center">Nuestros Grupos</h2>
      </v-card-text>
    </v-card> -->
    <!-- <v-container>
         <v-card class="hidden-xs white">
      <v-card-media height="100px">
            <img class="g-text center hidden-xs" src="../../assets/img/group/groups-text.png" alt="">
      </v-card-media>
    </v-card>
    </v-container> -->
  
    <div class="container">
      <div class="row">            <img class="center" src="../../assets/img/group/groups-text.png" alt="">

            <div class="col m4" v-for="(group, index) in groups" :key="index" >
            <div class="card z-depth-3">
              <div class="card-image waves-effect waves-block waves-light">
                <img class="activator" :src= group.image >
              </div>
              <div class="card-content">
                <span class="card-title activator grey-text text-darken-4">{{group.name}}<i class="material-icons right">more_vert</i></span>
                <!-- <p><a href="#">This is a link</a></p> -->
              </div>
              <div class="card-reveal">
                <span class="card-title white-text" >{{group.name}}<i class="material-icons right">close</i></span>
                <p>{{group.desc}}</p>
              </div>
          </div>
      </div>
  

      </div>
    </div>

     
  </div>
</template>

<script>
export default {
  name: 'groups',
  data(){
    return {
      groups: [
        {name: "Congregacional", image: require("../../assets/img/group/cong.jpg"), desc: "Eventos para toda la familia!"},
        {name: "Niños", image: require("../../assets/img/group/ninos.jpg"), desc: "Actividades para niños y niñas!"},
        {name: "Jovenes", image: require("../../assets/img/group/jovenes.jpg"), desc: "Actividades para jovenes donde pueden hacer nuevas amistades!"},
        {name: "Mujeres", image: require("../../assets/img/group/mujeres.jpg"), desc: "Classes & actividades con solo mujeres!"},
        {name: "Comunidad", image: require("../../assets/img/group/community.jpg"), desc: "Actividaded para ayudar la communidad!"},
        {name: "Ancianos", image: require("../../assets/img/group/old.jpg"), desc: "Convivencias con los hermanos majores!"},
      ]
    }
  }
  
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style lang="scss" scoped>
@import '../../assets/main.scss';
@import '../../assets/materialize.min.css';


#groups {
  position: relative;
  // height: 110vmin;
  background: white;
}
.card {
  opacity: .65;
  transition: .3s ease;
}
.card:hover {
  opacity: 1;
}
.card-content {
  span {
    font-size: 20px!important;
  }
}
.card-reveal {
  background: $gradient-dark;
  opacity: .95;
  color:white;
  span {
     font-size: 20px!important;
    font-weight: 400!important;


  }
  p {
    margin-top: 10px;
  }
}
.center {
  width: 150%;
  position: absolute;
  top: 47%;
  left: 22%;
  // z-index: 9;
  opacity: .5;
}

@media screen and (max-width: 1024px) {
  .card {
  opacity: .75;
  transition: .3s ease;
}
.card:hover {
  opacity: 1;
}
.card-content {
  span {
    font-size: 1.4vw!important;
  }
}
  .card-reveal {
  opacity: 1;
  span {
     font-size: 1.4vw!important;
  }
  }

}


   @media screen and (max-width: 748px) {

     #groups {
      position: relative;
      height: auto;
      background: white;
      padding-top: 80px;
    }

  .card {
    margin-top: 0px!important;
    opacity: 1;
    }

    .center {
  width: 100%;
  position: absolute;
  top: 50px;
  left: 50%;
  // z-index: 9;
  opacity: .8;
}

   
  .grid {
    position: relative;
    top:0px;
    
  }

.divider {
    position: relative;
    height: 6px;
    width: 93%;
    left: 0%;
    opacity: .9;
    border-radius: 10px;
    background: $gradient-2;
    transition: all .7s;
}


        }
</style>



